    @Test
    public void testPayrollsAddedWithBalanceFile() throws Exception {
        String psid = "123456789";

        Company company = DataLoadServices.newCompany(SourceSystemCode.QBDT, psid, false, ServiceCode.Tax);
        DataLoadServices.activateTaxServiceExceptBalanceFile(company);

        PayrollServices.beginUnitOfWork();
        company = Company.findCompany(psid, SourceSystemCode.QBDT);
        CompanyService companyService = company.getCompanyService(ServiceCode.Tax);
        assertNotNull(companyService);
        assertEquals("Company status is PendingBalanceFile prior to balance file submit", ServiceSubStatusCode.PendingBalanceFile, companyService.getStatusCd());
        PayrollServices.rollbackUnitOfWork();

        OFX ofx = OFXRequestGenerator.generateBalanceFile(psid, true);

        QBDTTestHelper.submitQBDTRequestStringResponse(ofx);

        PayrollServices.beginUnitOfWork();
        company = Company.findCompany(company.getSourceCompanyId(), company.getSourceSystemCd());
        companyService = company.getCompanyService(ServiceCode.Tax);
        assertEquals("Company status is ActiveCurrent after balance file submit", ServiceSubStatusCode.ActiveCurrent, companyService.getStatusCd());
        DomainEntitySet<PayrollRun> payrollRuns = PayrollRun.findPayrollRuns(company);
        assertEquals(5, payrollRuns.size());
        OFXAssert.assertPayrolls(ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIPAYROLLRUN(), company);
        //Verify that no fees charged for payroll in balance file
        DomainEntitySet<BillingDetail> billingDetails = Application.find(BillingDetail.class);
        assertEquals("Billing details", 0, billingDetails.size());
        PayrollServices.rollbackUnitOfWork();

    }

    /**
     * This test verifies that payroll send beyond the historic threshold are recorded but no FT, MMT and Fees is charged
     * for it.
     * Current threshold value for test is 2007, it needs to match prod(2011) once tests are fixed
     *
     * @throws Exception
     */
    @Test
    public void testDoNotRecordPayrollBeyondThreshold() throws Exception {
        //Todo Fix this test for threshold of 2011 when we have a single threshold value
        String psid = "123456789";
        PayrollServices.beginUnitOfWork();
        PSPDate.setPSPTime(SpcfCalendar.createInstance(2006, 02, 01, SpcfTimeZone.getLocalTimeZone()));
        PayrollServices.commitUnitOfWork();

        DataLoadServices.updateCAEDDPaymentTemplateSupportDate(SpcfCalendar.createInstance(2006, 1, 1));
        DataLoadServices.updateIRSPaymentTemplateSupportDate(SpcfCalendar.createInstance(2006, 1, 1));

        Company company = DataLoadServices.newCompany(SourceSystemCode.QBDT, psid, false, ServiceCode.Tax);
        DataLoadServices.activateTaxServiceExceptBalanceFile(company);

        PayrollServices.beginUnitOfWork();
        company = Company.findCompany(psid, SourceSystemCode.QBDT);
        CompanyService companyService = company.getCompanyService(ServiceCode.Tax);
        assertNotNull(companyService);
        assertEquals("Company status is PendingBalanceFile prior to balance file submit", ServiceSubStatusCode.PendingBalanceFile, companyService.getStatusCd());
        PayrollServices.rollbackUnitOfWork();

        OFX ofx = OFXRequestGenerator.generateBalanceFile(psid, false);
        ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getICOINFOMOD().setIDTFILEQTRSTART("20060101");
        QBDTTestHelper.submitQBDTRequestStringResponse(ofx);

        PayrollServices.beginUnitOfWork();
        PSPDate.setPSPTime(SpcfCalendar.createInstance(2006, 03, 01, SpcfTimeZone.getLocalTimeZone()));
        PayrollServices.commitUnitOfWork();

        DataLoadPalette.runSimpleTaxPayroll(company, new DateDTO(2006, 03, 15));

        PayrollServices.beginUnitOfWork();
        //Verify no financial transactions created for payroll beyond threshold
        company = Company.findCompany(company.getSourceCompanyId(), company.getSourceSystemCd());
        DomainEntitySet<FinancialTransaction> financialTransactions = Application.find(FinancialTransaction.class, FinancialTransaction.Company().equalTo(company));
        assertEquals(0, financialTransactions.size());
        //Verify no MMTs are created
        DomainEntitySet<MoneyMovementTransaction> moneyMovementTransactions = Application.find(MoneyMovementTransaction.class, MoneyMovementTransaction.Company().equalTo(company));
        assertEquals(0, moneyMovementTransactions.size());
        //Verify no fees is charged
        DomainEntitySet<BillingDetail> billingDetails = Application.find(BillingDetail.class);
        assertEquals("Billing details", 0, billingDetails.size());
        PayrollServices.rollbackUnitOfWork();

    }

    @Test
    public void testPayrollsAddedWithBalanceFile_WithoutOnServiceFlag() throws Exception {
        String psid = "123456789";

        Company company = DataLoadServices.newCompany(SourceSystemCode.QBDT, psid, false, ServiceCode.Tax);
        DataLoadServices.activateTaxServiceExceptBalanceFile(company);

        PayrollServices.beginUnitOfWork();
        company = Company.findCompany(psid, SourceSystemCode.QBDT);
        CompanyService companyService = company.getCompanyService(ServiceCode.Tax);
        assertNotNull(companyService);
        assertEquals("Company status is PendingBalanceFile prior to balance file submit", ServiceSubStatusCode.PendingBalanceFile, companyService.getStatusCd());
        PayrollServices.rollbackUnitOfWork();

        OFX ofx = OFXRequestGenerator.generateBalanceFile(psid, true);

        for (IPAYROLLRUN ipayrollrun : ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIPAYROLLRUN()) {
            for (IPAYCHK ipaychk : ipayrollrun.getIPAYCHK()) {
                ipaychk.setIONSERVICE(null);
            }
        }

        QBDTTestHelper.submitQBDTRequestStringResponse(ofx);

        PayrollServices.beginUnitOfWork();
        company = Company.findCompany(company.getSourceCompanyId(), company.getSourceSystemCd());
        companyService = company.getCompanyService(ServiceCode.Tax);
        assertEquals("Company status is ActiveCurrent after balance file submit", ServiceSubStatusCode.ActiveCurrent, companyService.getStatusCd());
        DomainEntitySet<PayrollRun> payrollRuns = PayrollRun.findPayrollRuns(company);
        assertEquals(5, payrollRuns.size());
        OFXAssert.assertPayrolls(ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIPAYROLLRUN(), company);
        PayrollServices.rollbackUnitOfWork();

    }


    @Test
    public void testVoidPayrollBeforeMaxDays() throws Exception {
        String psid = "123456789";

        PayrollServices.beginUnitOfWork();
        PSPDate.setPSPTime(SpcfCalendar.createInstance(2012, 02, 01, SpcfTimeZone.getLocalTimeZone()));
        PayrollServices.commitUnitOfWork();

        DataLoadServices.updateCAEDDPaymentTemplateSupportDate(SpcfCalendar.createInstance(2012, 1, 1));
        DataLoadServices.updateIRSPaymentTemplateSupportDate(SpcfCalendar.createInstance(2012, 1, 1));

        Company company = DataLoadServices.newCompany(SourceSystemCode.QBDT, psid, false, ServiceCode.Tax);
        DataLoadServices.activateTaxServiceExceptBalanceFile(company);

        PayrollServices.beginUnitOfWork();
        company = Company.findCompany(psid, SourceSystemCode.QBDT);
        CompanyService companyService = company.getCompanyService(ServiceCode.Tax);
        assertNotNull(companyService);
        assertEquals("Company status is PendingBalanceFile prior to balance file submit", ServiceSubStatusCode.PendingBalanceFile, companyService.getStatusCd());
        PayrollServices.rollbackUnitOfWork();

        OFX ofx = OFXRequestGenerator.generateBalanceFile(psid, false);
        ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getICOINFOMOD().setIDTFILEQTRSTART("20060101");
        QBDTTestHelper.submitQBDTRequestStringResponse(ofx);

        PayrollServices.beginUnitOfWork();
        PSPDate.setPSPTime(SpcfCalendar.createInstance(2012, 03, 12, SpcfTimeZone.getLocalTimeZone()));
        PayrollServices.commitUnitOfWork();

        DataLoadPalette.runSimpleTaxPayroll(company, new DateDTO(2012, 03, 14));


        DataLoadServices.runOffload();

        DataLoadServices.setPSPDate(2012, 3, 22);
        // Void PayrollRun
        PayrollServices.beginUnitOfWork();
        company = Company.findCompany(company.getSourceCompanyId(), company.getSourceSystemCd());

        PayrollRun payrollToVoid = PayrollRun.findPayrollRuns(company).get(0);
        VoidPayrollDTO voidPayrollDTO = new VoidPayrollDTO();
        voidPayrollDTO.setSourcePayrollRunId(payrollToVoid.getSourcePayRunId());
        List<String> paychecksToVoid = new ArrayList<String>();
        for (Paycheck paycheck : payrollToVoid.getPaycheckCollection()) {
            paychecksToVoid.add(paycheck.getSourcePaycheckId());
        }
        voidPayrollDTO.setPaycheckIdList(paychecksToVoid);
        ProcessResult voidProcessResult = null;
        try {
            voidProcessResult = PayrollServices.payrollManager.voidPayroll(SourceSystemCode.QBDT, company.getSourceCompanyId(), voidPayrollDTO);
        } catch (RuntimeException e) {
            Assert.assertTrue("exception equals", e.getMessage().contains("A created transaction is being added to a payment that is no longer pending.  " +
                                                                                  "Trying to add to FT:"));
        }

        PayrollServices.commitUnitOfWork();

    }

