    @Test
    public void testBalanceFileExistingDDPaychecks() throws Exception {
        DataLoadServices.updateIRSPaymentTemplateSupportDate(SpcfCalendar.createInstance(2011, 1, 1));

        DataLoadServices.setPSPDate(SpcfCalendar.createInstance(2011, 1, 20, SpcfTimeZone.getLocalTimeZone()));

        String psid = "123456789";

        Company company = DataLoadServices.newCompany(SourceSystemCode.QBDT, psid, false, ServiceCode.DirectDeposit, ServiceCode.Cloud);

        CompanyBankAccount companyBankAccount = DataLoadServices.addCompanyBankAccount(company);

        DataLoadServices.addCompanyPIN(company, null);

        List<Employee> employees = DataLoadServices.addEEs(company, 5, true, false);

        PayrollServices.beginUnitOfWork();
        PayrollRunDTO payrollRunDTO = DataLoadServices.createDDPayrollRun(company, companyBankAccount, new DateDTO(PSPDate.getPSPTime()), employees);
        int i = 1;
        for (PaycheckDTO paycheckDTO : payrollRunDTO.getPaychecks()) {
            paycheckDTO.setPaycheckId(Integer.toString(i++));
        }
        assertSuccess(PayrollServices.payrollManager.submitPayroll(company.getSourceSystemCd(), company.getSourceCompanyId(), payrollRunDTO));
        PayrollServices.commitUnitOfWork();


        DataLoadServices.runOffload();

        DataLoadServices.setPSPDate(SpcfCalendar.createInstance(2011, 1, 30, SpcfTimeZone.getLocalTimeZone()));
        DataLoadServices.addTaxService(company);
        DataLoadServices.activateTaxServiceExceptBalanceFile(company);

        OFX ofx = OFXRequestGenerator.generateBalanceFile(psid, true);
        QBDTTestHelper.submitQBDTRequestStringResponse(ofx);

        PayrollServices.beginUnitOfWork();
        Application.refresh(company);
        DomainEntitySet<PayrollRun> payrolls = PayrollRun.findPayrollRuns(company);
        assertEquals(6, payrolls.size());
        PayrollRun supersededPayrollRun = assertOne(payrolls.find(PayrollRun.PayrollRunType().equalTo(PayrollType.Regular)));
        assertEquals(5, payrolls.find(PayrollRun.PayrollRunType().equalTo(PayrollType.CloudOnly)).size());

        PayrollRun newPayrollRun = Paycheck.findPaycheck(company, "1").getPayrollRun();

        assertEquals(5, supersededPayrollRun.getPaycheckCollection().size());
        assertEquals(5, newPayrollRun.getPaycheckCollection().size());
        for (int j = 1; j <= 5; j++) {
            Paycheck newPaycheck = Paycheck.findPaycheck(company, Integer.toString(j));
            assertEquals(newPayrollRun, newPaycheck.getPayrollRun());
            Paycheck supersededPaycheck = Paycheck.findPaycheck(company, Integer.toString(-1 * j));
            assertEquals(supersededPayrollRun, supersededPaycheck.getPayrollRun());
        }

        OFXAssert.assertPayrolls(ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIPAYROLLRUN(), company);

        PayrollServices.commitUnitOfWork();

        DataLoadServices.setPSPDate(SpcfCalendar.createInstance(2011, 1, 31, SpcfTimeZone.getLocalTimeZone()));

        DataLoadServices.runOffload();

        DataLoadServices.setPSPDate(SpcfCalendar.createInstance(2011, 2, 5, SpcfTimeZone.getLocalTimeZone()));

        QBDTTestHelper.voidPaychecks(company, ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIPAYROLLRUN(), true);

    }


    @Test
    public void testSupersededVMPPayroll() {
        DataLoadServices.reinitialize();
        DataLoadServices.updateCAEDDPaymentTemplateSupportDate(SpcfCalendar.createInstance(2011, 1, 1));
        DataLoadServices.updateIRSPaymentTemplateSupportDate(SpcfCalendar.createInstance(2011, 1, 1));

        DataLoadServices.setPSPDate(SpcfCalendar.createInstance(2010, 12, 30, SpcfTimeZone.getLocalTimeZone()));

        DataLoadServices.employeeId = -1; //make everything match up
        Company company = DataLoadServices.newCompany(SourceSystemCode.QBDT, ServiceCode.DirectDeposit, ServiceCode.Cloud, ServiceCode.CloudV2, ServiceCode.ViewMyPaycheck);

        DataLoadServices.addFederalTaxCompanyLaws(company);
        DataLoadServices.addCompanyBankAccount(company);

        DataLoadServices.addCompanyPIN(company, null);

        DataLoadPalette.runSimpleTaxPayroll(company, new DateDTO(2011, 1, 10));

        DataLoadServices.addTaxService(company);
        DataLoadServices.activateTaxServiceExceptBalanceFile(company);

        Application.beginUnitOfWork();
        for (QbdtEmployeeInfo qbdtEmployeeInfo : Application.find(QbdtEmployeeInfo.class)) {
            qbdtEmployeeInfo.setIsAssisted(false);
        }
        Application.commitUnitOfWork();

        //now balf
        OFXRequestGenerator.setPayrollItemId(DataLoadServices.nextPayrollItemId());
        OFX ofx = OFXRequestGenerator.generateBalanceFile(company.getSourceCompanyId(), true);
        for (IPAYROLLRUN ipayrollrun : ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIPAYROLLRUN()) {
            for (IPAYCHK ipaychk : ipayrollrun.getIPAYCHK()) {
                ipaychk.setIAMT("0");
            }

        }
        QBDTTestHelper.submitQBDTRequestStringResponse(ofx);

        assertEquals(2, Application.find(PayrollRun.class, PayrollRun.PayrollRunStatus().equalTo(PayrollStatus.Superseded)).size());
    }

