    @Test
    public void testOFXHIREActIneligiblity() throws Exception {
        String psid = "123456789";

        PayrollServices.beginUnitOfWork();
        SystemParameter.update(Code.HIRE_ACT_ENABLED, "true");
        PayrollServices.commitUnitOfWork();

        Company company = DataLoadServices.newCompany(SourceSystemCode.QBDT, psid, false, ServiceCode.Tax);
        DataLoadServices.activateTaxServiceExceptBalanceFile(company);

        OFX ofx = QBDTTestHelper.submitBalanceFile(company, true);

        List<IPAYROLLRUN> payrollRuns = new ArrayList<IPAYROLLRUN>();
        List<IEMP> iemps = new ArrayList<IEMP>();
        iemps.add(ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIEMP().get(0));
        payrollRuns.add(OFXRequestGenerator.generatePayrollRun(iemps,
                                                               ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIPITEM(),
                                                               new Date("01/31/2011"),
                                                               new Date("01/31/2011"),
                                                               new Date("01/31/2011"),
                                                               true));
        for (IPAYCHK ipaychk : payrollRuns.get(0).getIPAYCHK()) {
            /*
             * Find the taxline corresponding to the CompanyLaw for SS ER (62)
             * and set the amount to zero. Also set relevant properties to some
             * dummy but legal values.
             */
            for (ITAXLINE itaxline : ipaychk.getITAXLINE()) {
                PayrollServices.beginUnitOfWork();
                String lawId = CompanyLaw.findCompanyLawBySourceId(company, itaxline.getIPITEMID()).getLaw().getLawId();
                PayrollServices.rollbackUnitOfWork();

                if ("62".equals(lawId)) {
                    itaxline.setIAMT("10.0");   /*  Set SS ER to non-zero   */
                    itaxline.setITAXABLEWAGE("1000.0");
                    itaxline.setIWB("250.0");
                }
            }
        }

        List<IPAYROLLTX> liabilityAdjustments = new ArrayList<IPAYROLLTX>();
        List<ITXLINE> itxlines = new ArrayList<ITXLINE>();
        int lineCount = 0;
        for (IPITEM payrollItem : ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIPITEM()) {
            itxlines.add(OFXRequestGenerator.generateTransactionLine(null,
                                                                     new SpcfMoney(SpcfDecimal.createInstance(lineCount)),
                                                                     "Class" + lineCount,
                                                                     false,
                                                                     "Memo" + lineCount,
                                                                     payrollItem.getIPITEMID(),
                                                                     new SpcfMoney(SpcfDecimal.createInstance(lineCount + 1)),
                                                                     new SpcfMoney(SpcfDecimal.createInstance(lineCount + 2))));
        }
        for (IEMP iemp : iemps) {
            String empId = iemp.getIEMPID();
            liabilityAdjustments.add(OFXRequestGenerator.generatePayrollTransaction("Account" + empId,
                                                                                    new SpcfMoney(SpcfDecimal.createInstance(empId)),
                                                                                    "1",
                                                                                    new Date("01/31/2011"),
                                                                                    new Date("01/31/2011"),
                                                                                    empId,
                                                                                    "Memo " + empId,
                                                                                    "Agency" + empId,
                                                                                    true,
                                                                                    QBOFX.OFXPayrollTransactionTransactionType.LIABADJ,
                                                                                    "Ref" + empId,
                                                                                    false,
                                                                                    itxlines));
        }
        OFX adjustmentOfx = new OFX();
        adjustmentOfx.setSIGNONMSGSRQV1(OFXRequestGenerator.generateSignOnMessage(psid, DataLoadServices.PIN));
        IPAYROLLTRNRQ ipayrolltrnrq = OFXRequestGenerator.generatePayrollRequest(false,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 liabilityAdjustments,
                                                                                 null,
                                                                                 null,
                                                                                 payrollRuns);
        adjustmentOfx.setIPAYROLLMSGSRQV1(OFXRequestGenerator.generatePayrollMessage(company, true, ipayrolltrnrq));
        QBDTTestHelper.submitQBDTRequestStringResponse(adjustmentOfx);

        PayrollServices.beginUnitOfWork();
        company = Company.findCompany(company.getSourceCompanyId(), company.getSourceSystemCd());
        DomainEntitySet<PayrollRun> domainPayrollRuns = PayrollRun.findPayrollRuns(company);
        assertEquals(2, domainPayrollRuns.size());
        for (PayrollRun domainPayrollRun : domainPayrollRuns) {
            for (LiabilityAdjustment liabilityAdjustment : domainPayrollRun.getLiabilityAdjustmentCollection()) {
                if ("62".equals(liabilityAdjustment.getLaw().getLawId())) {
                    assertEquals(0, liabilityAdjustment.getPayItemCollection().size());
                }
            }
        }
        PayrollServices.rollbackUnitOfWork();
    }

    @Test
    public void testDuplicatePaycheckIds() throws Exception {
        String psid = "123456789";

        Company company = DataLoadServices.newCompany(SourceSystemCode.QBDT, psid, false, ServiceCode.Tax);
        DataLoadServices.activateTaxServiceExceptBalanceFile(company);

        OFX ofx = OFXRequestGenerator.generateBalanceFile(psid, false, false, true, false);
        QBDTTestHelper.submitQBDTRequestStringResponse(ofx);


        List<IPAYROLLRUN> ofxPayrollRuns = new ArrayList<IPAYROLLRUN>();
        IPAYROLLRUN ofxPayrollRun =
                OFXRequestGenerator.generatePayrollRun(ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIEMP(),
                                                       ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIPITEM(),
                                                       new Date("01/31/2011"),
                                                       new Date("01/31/2011"),
                                                       new Date("01/31/2011"),
                                                       true);
        // duplicate the paycheck in the request
        ofxPayrollRun.getIPAYCHK().add(ofxPayrollRun.getIPAYCHK().get(0));
        ofxPayrollRuns.add(ofxPayrollRun);

        OFX payrollOfx = new OFX();
        payrollOfx.setSIGNONMSGSRQV1(OFXRequestGenerator.generateSignOnMessage(psid, DataLoadServices.PIN));
        IPAYROLLTRNRQ ipayrolltrnrq = OFXRequestGenerator.generatePayrollRequest(false,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 ofxPayrollRuns);
        payrollOfx.setIPAYROLLMSGSRQV1(OFXRequestGenerator.generatePayrollMessage(company, true, ipayrolltrnrq));

        QBDTTestHelper.submitQBDTRequestStringResponse(payrollOfx);

        PayrollServices.beginUnitOfWork();
        company = Company.findCompany(company.getSourceCompanyId(), company.getSourceSystemCd());
        // the adjustments should be included in the same payroll becase they all have the same date
        DomainEntitySet<PayrollRun> domainPayrollRuns = PayrollRun.findPayrollRuns(company);
        assertEquals(1, domainPayrollRuns.size());
        OFXAssert.assertPayrolls(payrollOfx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIPAYROLLRUN(), company);
        OFXAssert.assertPayrollTransactions(payrollOfx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIPAYROLLTX(), company);
        PayrollServices.rollbackUnitOfWork();

    }

    @Test
    public void testOFXHIREActTotalReductions() throws Exception {
        String psid = "123456789";

        PayrollServices.beginUnitOfWork();
        SystemParameter.update(Code.HIRE_ACT_ENABLED, "true");
        PayrollServices.commitUnitOfWork();

        Company company = DataLoadServices.newCompany(SourceSystemCode.QBDT, psid, false, ServiceCode.Tax);
        DataLoadServices.activateTaxServiceExceptBalanceFile(company);

        OFX ofx = QBDTTestHelper.submitBalanceFile(company, true);

        List<IPAYROLLRUN> payrollRuns = new ArrayList<IPAYROLLRUN>();
        List<IEMP> iemps = new ArrayList<IEMP>();
        iemps.add(ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIEMP().get(0));
        iemps.add(ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIEMP().get(1));
        iemps.add(ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIEMP().get(2));

        payrollRuns.add(OFXRequestGenerator.generatePayrollRun(iemps,
                                                               ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIPITEM(),
                                                               new Date("01/31/2011"),
                                                               new Date("01/31/2011"),
                                                               new Date("01/31/2011"),
                                                               false));
        for (IPAYCHK ipaychk : payrollRuns.get(0).getIPAYCHK()) {
            /*
             * Find the tax lines corresponding to the CompanyLaw for SS ER (62) & SS EE (61)
             * and set the amount to 0.0 & 6.2*250 respectively. Also set relevant properties to some
             * dummy but legal values.
             */
            for (ITAXLINE itaxline : ipaychk.getITAXLINE()) {
                PayrollServices.beginUnitOfWork();
                String lawId = CompanyLaw.findCompanyLawBySourceId(company, itaxline.getIPITEMID()).getLaw().getLawId();
                PayrollServices.rollbackUnitOfWork();
                if ("62".equals(lawId)) {
                    itaxline.setIAMT("0.0");    /*  Zero for SS ER  */
                    itaxline.setITAXABLEWAGE("1000.0");
                    itaxline.setIWB("250.0");
                } else if ("61".equals(lawId)) {
                    itaxline.setIAMT("-15.5");    /*  -6.2%*250  for SS EE */
                    itaxline.setITAXABLEWAGE("1000.0");
                    itaxline.setIWB("250.0");
                }
            }
        }

        List<IPAYROLLTX> liabilityAdjustments = new ArrayList<IPAYROLLTX>();
        List<ITXLINE> itxlines = new ArrayList<ITXLINE>();

        for (IPITEM payrollItem : ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIPITEM()) {
            PayrollServices.beginUnitOfWork();
            String lawId = CompanyLaw.findCompanyLawBySourceId(company, payrollItem.getIPITEMID()).getLaw().getLawId();
            PayrollServices.rollbackUnitOfWork();
            /*  Only pitem corresponding to 62 amt. +6.2*250 */
            if ("62".equals(lawId)) {
                itxlines.add(OFXRequestGenerator.generateTransactionLine(null,
                                                                         new SpcfMoney("46.5"),
                                                                         "Class",
                                                                         false,
                                                                         "Memo",
                                                                         payrollItem.getIPITEMID(),
                                                                         new SpcfMoney("250.0"),   /*  250 */
                                                                         new SpcfMoney("1000.0"))); /*  1000    */
            }
        }
        /*for (IEMP iemp : iemps) */
        {
            liabilityAdjustments.add(OFXRequestGenerator.generatePayrollTransaction(
                    null,
                    new SpcfMoney("46.5"),
                    null,
                    new Date("01/31/2011"),
                    new Date("01/31/2011"),
                    iemps.get(0).getIEMPID(),
                    null,
                    null,
                    true,
                    QBOFX.OFXPayrollTransactionTransactionType.LIABADJ,
                    null,
                    false,
                    itxlines)
            );
        }
        OFX adjustmentOfx = new OFX();
        adjustmentOfx.setSIGNONMSGSRQV1(OFXRequestGenerator.generateSignOnMessage(psid, DataLoadServices.PIN));
        IPAYROLLTRNRQ ipayrolltrnrq = OFXRequestGenerator.generatePayrollRequest(false,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 liabilityAdjustments,
                                                                                 null,
                                                                                 null,
                                                                                 payrollRuns);
        adjustmentOfx.setIPAYROLLMSGSRQV1(OFXRequestGenerator.generatePayrollMessage(company, true, ipayrolltrnrq));

        QBDTTestHelper.submitQBDTRequestStringResponse(adjustmentOfx);

        PayrollServices.beginUnitOfWork();
        company = Company.findCompany(company.getSourceCompanyId(), company.getSourceSystemCd());
        DomainEntitySet<PayrollRun> domainPayrollRuns = PayrollRun.findPayrollRuns(company);
        assertEquals(2, domainPayrollRuns.size());
        for (PayrollRun payrollRun : domainPayrollRuns) {
            if (payrollRun.getPaycheckCollection().size() > 0) {
                assertEquals(3, payrollRun.getPaycheckCollection().size());
            } else {
                assertEquals(1, payrollRun.getLiabilityAdjustmentCollection().size());
                /*LiabilityAdjustment liabilityAdjustment=payrollRun.getLiabilityAdjustmentCollection().get(0);*/
                for (LiabilityAdjustment liabilityAdjustment : payrollRun.getLiabilityAdjustmentCollection()) {
                    assertEquals(SpcfMoney.ZERO, liabilityAdjustment.getAmount());
                    assertEquals(3, liabilityAdjustment.getPayItemCollection().size());
                    for (PayItem payItem : liabilityAdjustment.getPayItemCollection()) {
                        assertEquals(new DateDTO("2011-01-31").toSpcfCalendar(), payItem.getEffectiveDate().toLocal());
                        assertEquals(new SpcfMoney("15.5"), payItem.getAmount());
                    }
                }
            }
        }
        PayrollServices.rollbackUnitOfWork();
    }

    @Test
    public void testLiabilityCheck_Paychecks() throws Exception {
        String psid = "123456789";
        DataLoadServices.updateIRSPaymentTemplateSupportDate(SpcfCalendar.createInstance(2008, 1, 1));

        Company company = DataLoadServices.newCompany(SourceSystemCode.QBDT, psid, false, ServiceCode.Tax);
        DataLoadServices.activateTaxServiceExceptBalanceFile(company);

        OFX ofx = QBDTTestHelper.submitBalanceFile(company, true);

        DataLoadServices.setPSPDate(SpcfCalendar.createInstance(2011, 2, 7));

        List<IPAYROLLRUN> ipayrollruns = QBDTTestHelper.submitPayroll(company,
                                                                      ofx,
                                                                      new Date("01/31/2011"),
                                                                      new Date("01/31/2011"),
                                                                      new Date("01/31/2011"));

        // recall with amount
        List<IPAYROLLTX> liabilityAdjustments = new ArrayList<IPAYROLLTX>();
        List<ITXLINE> itxlines = new ArrayList<ITXLINE>();
        for (IPITEM payrollItem : ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIPITEM()) {
            itxlines.add(OFXRequestGenerator.generateTransactionLine(null,
                                                                     new SpcfMoney(SpcfDecimal.createInstance(QBOFX.mapOFXStringToBoolean(payrollItem.getIISEMP()) ? "-" + payrollItem.getIPITEMID() : payrollItem.getIPITEMID())),
                                                                     "Class" + payrollItem.getIPITEMID(),
                                                                     false,
                                                                     "Memo" + payrollItem.getIPITEMID(),
                                                                     payrollItem.getIPITEMID(),
                                                                     new SpcfMoney(SpcfDecimal.createInstance(payrollItem.getIPITEMID() + 1)),
                                                                     new SpcfMoney(SpcfDecimal.createInstance(payrollItem.getIPITEMID() + 2))));
        }
        for (int i = 0; i < 2; i++) {
            liabilityAdjustments.add(OFXRequestGenerator.generatePayrollTransaction("Account" + i,
                                                                                    new SpcfMoney(SpcfDecimal.createInstance(i)),
                                                                                    "" + i,
                                                                                    new Date("01/31/2011"),
                                                                                    new Date("01/31/2011"),
                                                                                    null,
                                                                                    "Memo " + i,
                                                                                    "Agency" + i,
                                                                                    true,
                                                                                    QBOFX.OFXPayrollTransactionTransactionType.LIABADJ,
                                                                                    "Ref" + i,
                                                                                    false,
                                                                                    itxlines));
        }

        List<IPAYROLLRUN> voidPayrolls = new ArrayList<IPAYROLLRUN>();
        for (IPAYROLLRUN ipayrollrun : ipayrollruns) {
            IPAYROLLRUN voidIpayrollrun = new IPAYROLLRUN();
            voidIpayrollrun.setIDTPAYCHKS(ipayrollrun.getIDTPAYCHKS());
            for (IPAYCHK ipaychk : ipayrollrun.getIPAYCHK()) {
                IPAYCHK ipaychkmod = new IPAYCHK();
                ipaychkmod.setIPAYCHKID(ipaychk.getIPAYCHKID());
                ipaychkmod.setIEMPID(ipaychk.getIEMPID());
                ipaychkmod.setIPAYCHKTYPE(ipaychk.getIPAYCHKTYPE());
                ipaychkmod.setIEMPNAME(ipaychk.getIEMPNAME());
                ipaychkmod.setICLASS(ipaychk.getICLASS());
                ipaychkmod.setIACCTNAME(ipaychk.getIACCTNAME());
                ipaychkmod.setIPAYCHKINFO(ipaychk.getIPAYCHKINFO());
                ipaychkmod.getIPAYCHKINFO().setICHKNUM("c" + ipaychkmod.getIPAYCHKINFO().getICHKNUM());
                ipaychkmod.setIVOID("Y");
                ipaychkmod.setIDTPAYPDBEGIN(ipaychk.getIDTPAYPDBEGIN());
                ipaychkmod.setIDTPAYPDEND(ipaychk.getIDTPAYPDEND());
                ipaychkmod.setIMEMO(ipaychk.getIMEMO());
                ipaychkmod.setICLEARED("9");
                ipaychkmod.setIONSERVICE("Y");
                voidIpayrollrun.getIPAYCHKMOD().add(ipaychkmod);
            }
            voidPayrolls.add(voidIpayrollrun);
        }

        OFX adjustmentOfx = new OFX();
        adjustmentOfx.setSIGNONMSGSRQV1(OFXRequestGenerator.generateSignOnMessage(psid, DataLoadServices.PIN));
        IPAYROLLTRNRQ ipayrolltrnrq = OFXRequestGenerator.generatePayrollRequest(false,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 liabilityAdjustments,
                                                                                 null,
                                                                                 null,
                                                                                 voidPayrolls);
        adjustmentOfx.setIPAYROLLMSGSRQV1(OFXRequestGenerator.generatePayrollMessage(company, true, ipayrolltrnrq));

        com.intuit.sbd.payroll.psp.common.ofx.response.OFX response = QBDTTestHelper.submitQBDTRequest(adjustmentOfx);
        assertNotNull("Response", response);
    }


