    @Test
    public void testVoidBeforeServiceStartDate() throws Exception {
        String psid = "123456789";
        DataLoadServices.updateIRSPaymentTemplateSupportDate(SpcfCalendar.createInstance(2008, 1, 1));

        Company company = DataLoadServices.newCompany(SourceSystemCode.QBDT, psid, false, ServiceCode.Tax);
        DataLoadServices.activateTaxServiceExceptBalanceFile(company);
        DataLoadServices.claimNoFeesOffer(company);

        OFX ofx = OFXRequestGenerator.generateBalanceFile(company.getSourceCompanyId(), false, false, false);
        ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getICOINFOMOD().setIDTFILEQTRSTART(QBOFX.getDTTXResponse(new Date("04/01/2011")));

        QBDTTestHelper.submitQBDTRequest(ofx);

        DataLoadServices.setPSPDate(SpcfCalendar.createInstance(2011, 4, 10));

        // submit a back dated payroll
        List<IPAYROLLRUN> payrollRuns = new ArrayList<IPAYROLLRUN>();
        payrollRuns.add(OFXRequestGenerator.generatePayrollRun(ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIEMP(),
                                                               ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIPITEM(),
                                                               new Date("01/31/2011"),
                                                               new Date("01/31/2011"),
                                                               new Date("01/31/2011"),
                                                               false));

        PayrollServices.beginUnitOfWork();
        // find aeic
        CompanyLaw companyLaw = CompanyLaw.findCompanyLaw(company, "143");
        PayrollServices.rollbackUnitOfWork();

        // updated the tax amounts to match the payroll item id
        for (IPAYROLLRUN payrollRun : payrollRuns) {
            for (IPAYCHK ipaychk : payrollRun.getIPAYCHK()) {
                for (Iterator<ITAXLINE> iterator = ipaychk.getITAXLINE().iterator(); iterator.hasNext(); ) {
                    ITAXLINE itaxline = iterator.next();
                    if (itaxline.getIPITEMID().equals(companyLaw.getSourceId())) {
                        iterator.remove();
                    } else {
                        if (itaxline.getIAMT().contains("-")) {
                            itaxline.setIAMT("$-" + itaxline.getIPITEMID() + ".00");
                        } else {
                            itaxline.setIAMT("$" + itaxline.getIPITEMID() + ".00");
                        }
                    }
                }
            }
        }

        OFX payrollOfx = new OFX();
        payrollOfx.setSIGNONMSGSRQV1(OFXRequestGenerator.generateSignOnMessage(company.getSourceCompanyId(), DataLoadServices.PIN));
        IPAYROLLTRNRQ ipayrolltrnrq = OFXRequestGenerator.generatePayrollRequest(false,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 payrollRuns);
        payrollOfx.setIPAYROLLMSGSRQV1(OFXRequestGenerator.generatePayrollMessage(company, true, ipayrolltrnrq));

        com.intuit.sbd.payroll.psp.common.ofx.response.OFX response = QBDTTestHelper.submitQBDTRequest(payrollOfx);
        assertNull("Payroll response", response.getIPAYROLLMSGSRSV1().getIPAYROLLUPDATERS().getIPAYROLLTRNRS().getIPAYROLLRS());

        // void the payroll
        List<IPAYROLLRUN> voidPayrolls = new ArrayList<IPAYROLLRUN>();
        for (IPAYROLLRUN ipayrollrun : payrollRuns) {
            IPAYROLLRUN voidIpayrollrun = new IPAYROLLRUN();
            voidIpayrollrun.setIDTPAYCHKS(ipayrollrun.getIDTPAYCHKS());
            for (IPAYCHK ipaychk : ipayrollrun.getIPAYCHK()) {
                IPAYCHK ipaychkmod = new IPAYCHK();
                ipaychkmod.setIPAYCHKID(ipaychk.getIPAYCHKID());
                ipaychkmod.setIEMPID(ipaychk.getIEMPID());
                ipaychkmod.setIPAYCHKTYPE(ipaychk.getIPAYCHKTYPE());
                ipaychkmod.setIEMPNAME(ipaychk.getIEMPNAME());
                ipaychkmod.setICLASS(ipaychk.getICLASS());
                ipaychkmod.setIACCTNAME(ipaychk.getIACCTNAME());
                ipaychkmod.setIPAYCHKINFO(ipaychk.getIPAYCHKINFO());
                ipaychkmod.getIPAYCHKINFO().setICHKNUM("c" + ipaychkmod.getIPAYCHKINFO().getICHKNUM());
                ipaychkmod.setIVOID("Y");
                ipaychkmod.setIDTPAYPDBEGIN(ipaychk.getIDTPAYPDBEGIN());
                ipaychkmod.setIDTPAYPDEND(ipaychk.getIDTPAYPDEND());
                ipaychkmod.setIMEMO(ipaychk.getIMEMO());
                ipaychkmod.setICLEARED("9");
                ipaychkmod.setIONSERVICE("Y");
                voidIpayrollrun.getIPAYCHKMOD().add(ipaychkmod);
            }
            voidPayrolls.add(voidIpayrollrun);
        }

        OFX adjustmentOfx = new OFX();
        adjustmentOfx.setSIGNONMSGSRQV1(OFXRequestGenerator.generateSignOnMessage(psid, DataLoadServices.PIN));
        ipayrolltrnrq = OFXRequestGenerator.generatePayrollRequest(false,
                                                                   null,
                                                                   null,
                                                                   null,
                                                                   null,
                                                                   null,
                                                                   null,
                                                                   null,
                                                                   null,
                                                                   null,
                                                                   null,
                                                                   voidPayrolls);
        adjustmentOfx.setIPAYROLLMSGSRQV1(OFXRequestGenerator.generatePayrollMessage(company, true, ipayrolltrnrq));

        response = QBDTTestHelper.submitQBDTRequest(adjustmentOfx);
        assertEquals("Payroll response", 0, response.getIPAYROLLMSGSRSV1().getIPAYROLLUPDATERS().getIPAYROLLTRNRS().getIPAYROLLRS().getIPAYROLLTXMOD().size());
        assertEquals("Payroll response", 0, response.getIPAYROLLMSGSRSV1().getIPAYROLLUPDATERS().getIPAYROLLTRNRS().getIPAYROLLRS().getIPAYROLLTX().size());

        PayrollServices.beginUnitOfWork();
        DomainEntitySet<FinancialTransaction> financialTransactions = Application.find(FinancialTransaction.class, FinancialTransaction.Company().equalTo(company)
                                                                                                                                       .And(FinancialTransaction.TransactionType().AssociationType().equalTo(TransactionAssociationType.Impound)));
        assertEquals(0, financialTransactions.size());
        PayrollServices.rollbackUnitOfWork();
    }

