            assertEquals("void", "N", ipayrolltx.getIVOID());
            assertEquals("memo", QBOFX.MEMOS.CREATED_BY_PAYROLL_SERVICE + QBOFX.DATE_FORMATTER.format(SpcfUtils.convertSpcfCalendarToDate(PSPDate.getPSPTime())), ipayrolltx.getIMEMO());
