    public void testLiabilityCheck_VoidBeforePayment_Resubmit() throws Exception {
        String psid = "123456789";
        DataLoadServices.updateIRSPaymentTemplateSupportDate(SpcfCalendar.createInstance(2008, 1, 1));

        Company company = DataLoadServices.newCompany(SourceSystemCode.QBDT, psid, false, ServiceCode.Tax);
        DataLoadServices.activateTaxServiceExceptBalanceFile(company);
        DataLoadServices.claimNoFeesOffer(company);

        OFX ofx = QBDTTestHelper.submitBalanceFile(company, true);

        List<IPAYROLLRUN> payrollRuns = QBDTTestHelper.submitPayroll(company,
                                                                     ofx,
                                                                     new Date("01/31/2011"),
                                                                     new Date("01/31/2011"),
                                                                     new Date("01/31/2011"));

        // offload the payroll
        DataLoadServices.runOffload(company, SpcfCalendar.createInstance(2011, 1, 27));

        // void some of the paychecks after offload
        com.intuit.sbd.payroll.psp.common.ofx.response.OFX response = QBDTTestHelper.voidPaychecks(company, payrollRuns, true);
        IPAYROLLRS ipayrollrs = response.getIPAYROLLMSGSRSV1().getIPAYROLLUPDATERS().getIPAYROLLTRNRS().getIPAYROLLRS();
        assertNotNull("Payroll response", ipayrollrs);

        // verify the void mod
        assertEquals("liability checks", 1, ipayrollrs.getIPAYROLLTXMOD().size());
        com.intuit.sbd.payroll.psp.common.ofx.response.IPAYROLLTX ipayrolltxmod = ipayrollrs.getIPAYROLLTXMOD().get(0);

        PayrollServices.beginUnitOfWork();
        company = Company.findCompany(company.getSourceCompanyId(), company.getSourceSystemCd());
        CompanyBankAccount companyBankAccount = company.getCompanyBankAccountCollection().get(0);
        assertEquals("account name", companyBankAccount.getSourceBankAccountName(), ipayrolltxmod.getIACCTNAME());
        assertEquals("cleared", "0", ipayrolltxmod.getICLEARED());
        assertEquals("on service", "Y", ipayrolltxmod.getIONSERVICE());
        assertEquals("void", "N", ipayrolltxmod.getIVOID());
        assertEquals("name", QBOFX.AGENCIES.QUICKBOOKS_PAYROLL_SERVICE, ipayrolltxmod.getINAME());
        assertEquals("memo", QBOFX.MEMOS.VOID.ADJUSTED_FOR_VOIDED_PAYCHECK, ipayrolltxmod.getIMEMO());

        DomainEntitySet<PayrollRun> domainPayrollRuns = PayrollRun.findPayrollRuns(company);
        assertEquals(1, domainPayrollRuns.size());
        PayrollRun payrollRun = domainPayrollRuns.get(0);
        assertEquals("period end date", QBOFX.getDTTXResponse(SpcfUtils.convertSpcfCalendarToDate(payrollRun.getPaycheckDate())), ipayrolltxmod.getIDTPAYPDEND());
        FinancialTransaction debit = payrollRun.getFinancialTransactionCollection().findEntity(FinancialTransaction.TransactionType().TransactionTypeCd().equalTo(TransactionTypeCode.EmployerTaxDebit));
        assertNotNull("er debit", debit);
        assertEquals("transaction date", QBOFX.getDTTXResponse(SpcfUtils.convertSpcfCalendarToDate(debit.getSettlementDate())), ipayrolltxmod.getIDTTX());

        // two paychecks were voided
        int voidTotal = 0;
        int total = 0;
        List<com.intuit.sbd.payroll.psp.common.ofx.response.ITXLINE> nonTaxLines = new ArrayList<com.intuit.sbd.payroll.psp.common.ofx.response.ITXLINE>();
        for (com.intuit.sbd.payroll.psp.common.ofx.response.ITXLINE itxline : ipayrolltxmod.getITXLINE()) {
            if (itxline.getIACCTNAME() == null) {
                assertNotNull("payroll item id", itxline.getIPITEMID());
                int voidAmount = Integer.parseInt(itxline.getIPITEMID()) * 2;
                voidTotal += voidAmount;
                total += voidAmount;
                int amount = Integer.parseInt(itxline.getIPITEMID()) * 3;
                total += amount;

                assertEquals("memo", QBOFX.MEMOS.VOID.ADJUSTED_FOR_VOIDED_PAYCHECK, itxline.getIMEMO());
                assertEquals("amount", "$" + amount + ".00", itxline.getIAMT());
            } else {
                nonTaxLines.add(itxline);
            }
        }

        assertEquals("nontax lines", 3, nonTaxLines.size());
        for (com.intuit.sbd.payroll.psp.common.ofx.response.ITXLINE nonTaxLine : nonTaxLines) {
            if (QBOFX.ACCOUNTS.ASSET_ACCOUNT_NAME.equals(nonTaxLine.getIACCTNAME())) {
                assertEquals("amount", "$" + voidTotal + ".00", nonTaxLine.getIAMT());
                assertEquals("memo", QBOFX.MEMOS.VOID.EXCESS_TAX_RESULT_OF_VOID, nonTaxLine.getIMEMO());
            }
        }

        assertEquals("amount", "$-" + total + ".00", ipayrolltxmod.getIAMT());

        PayrollServices.rollbackUnitOfWork();

        payrollRuns = new ArrayList<IPAYROLLRUN>();
        payrollRuns.add(OFXRequestGenerator.generatePayrollRun(ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIEMP(),
                                                               ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIPITEM(),
                                                               new Date("02/02/2011"),
                                                               new Date("02/02/2011"),
                                                               new Date("02/02/2011"),
                                                               false));

        // updated the tax amounts to match the payroll item id
        for (IPAYROLLRUN payrollRun2 : payrollRuns) {
            for (IPAYCHK ipaychk : payrollRun2.getIPAYCHK()) {
                for (ITAXLINE itaxline : ipaychk.getITAXLINE()) {
                    if (itaxline.getIAMT().contains("-")) {
                        itaxline.setIAMT("$-" + itaxline.getIPITEMID() + ".00");
                    } else {
                        itaxline.setIAMT("$" + itaxline.getIPITEMID() + ".00");
                    }
                }
            }
        }

        OFX payrollOfx = new OFX();
        payrollOfx.setSIGNONMSGSRQV1(OFXRequestGenerator.generateSignOnMessage(psid, DataLoadServices.PIN));
        IPAYROLLTRNRQ ipayrolltrnrq = OFXRequestGenerator.generatePayrollRequest(false,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 payrollRuns);
        payrollOfx.setIPAYROLLMSGSRQV1(OFXRequestGenerator.generatePayrollMessage(company, true, ipayrolltrnrq));

        response = QBDTTestHelper.submitQBDTRequest(payrollOfx);
        ipayrollrs = response.getIPAYROLLMSGSRSV1().getIPAYROLLUPDATERS().getIPAYROLLTRNRS().getIPAYROLLRS();
        assertNotNull("Payroll response", ipayrollrs);

        // verify
        assertEquals("liability checks", 1, ipayrollrs.getIPAYROLLTX().size());
        com.intuit.sbd.payroll.psp.common.ofx.response.IPAYROLLTX ipayrolltx = ipayrollrs.getIPAYROLLTX().get(0);

        PayrollServices.beginUnitOfWork();
        company = Company.findCompany(company.getSourceCompanyId(), company.getSourceSystemCd());
        companyBankAccount = company.getCompanyBankAccountCollection().get(0);
        assertEquals("account name", companyBankAccount.getSourceBankAccountName(), ipayrolltx.getIACCTNAME());
        assertEquals("cleared", "0", ipayrolltx.getICLEARED());
        assertEquals("on service", "Y", ipayrolltx.getIONSERVICE());
        assertEquals("void", "N", ipayrolltx.getIVOID());
        assertEquals("name", QBOFX.AGENCIES.QUICKBOOKS_PAYROLL_SERVICE, ipayrolltx.getINAME());
        assertEquals("memo", QBOFX.MEMOS.CREATED_BY_PAYROLL_SERVICE + QBOFX.DATE_FORMATTER.format(SpcfUtils.convertSpcfCalendarToDate(PSPDate.getPSPTime())), ipayrolltx.getIMEMO());

        domainPayrollRuns = PayrollRun.findPayrollRuns(company);
        assertEquals(2, domainPayrollRuns.size());
        payrollRun = domainPayrollRuns.findEntity(PayrollRun.PaycheckDate().equalTo(CalendarUtils.convertToSpcfCalendar(new Date("02/02/2011"))));
        assertEquals("period end date", QBOFX.getDTTXResponse(SpcfUtils.convertSpcfCalendarToDate(payrollRun.getPaycheckDate())), ipayrolltx.getIDTPAYPDEND());
        debit = payrollRun.getFinancialTransactionCollection().findEntity(FinancialTransaction.TransactionType().TransactionTypeCd().equalTo(TransactionTypeCode.EmployerTaxDebit));
        assertNotNull("er debit", debit);
        assertEquals("transaction date", QBOFX.getDTTXResponse(SpcfUtils.convertSpcfCalendarToDate(debit.getSettlementDate())), ipayrolltx.getIDTTX());

        total = 0;
        nonTaxLines = new ArrayList<com.intuit.sbd.payroll.psp.common.ofx.response.ITXLINE>();
        for (com.intuit.sbd.payroll.psp.common.ofx.response.ITXLINE itxline1 : ipayrolltx.getITXLINE()) {
            if (itxline1.getIACCTNAME() == null) {
                assertNotNull("payroll item id", itxline1.getIPITEMID());
                int amount = Integer.parseInt(itxline1.getIPITEMID()) * 5;
                total += amount;

                assertEquals("amount", "$" + amount + ".00", itxline1.getIAMT());
            } else {
                nonTaxLines.add(itxline1);
            }
        }

        assertEquals("nontax lines", 3, nonTaxLines.size());
        voidTotal = -(int) QBOFX.mapOFXStringToDouble(ipayrolltx.getIAMT()) - total;
        for (com.intuit.sbd.payroll.psp.common.ofx.response.ITXLINE nonTaxLine : nonTaxLines) {
            if (QBOFX.ACCOUNTS.ASSET_ACCOUNT_NAME.equals(nonTaxLine.getIACCTNAME())) {
                assertEquals("amount", "$" + voidTotal + ".00", nonTaxLine.getIAMT());
                assertEquals("memo", QBOFX.MEMOS.DEBIT_REDUCED.APPLIED_EXCESS_TAX_FUNDS, nonTaxLine.getIMEMO());
            }
        }

        assertEquals("amount", "$-" + (total + voidTotal) + ".00", ipayrolltx.getIAMT());

        PayrollServices.rollbackUnitOfWork();

    }

