    @Test
    public void testPayroll_PaylineUpdates() throws Exception {
        String psid = "123456789";

        Company company = DataLoadServices.newCompany(SourceSystemCode.QBDT, psid, false, ServiceCode.Tax);
        DataLoadServices.activateTaxServiceExceptBalanceFile(company);

        OFX ofx = OFXRequestGenerator.generateBalanceFile(psid, false, false, false);

        QBDTTestHelper.submitQBDTRequestStringResponse(ofx);

        List<IPAYROLLRUN> payrollRuns = new ArrayList<IPAYROLLRUN>();
        payrollRuns.add(OFXRequestGenerator.generatePayrollRun(ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIEMP(),
                                                               ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIPITEM(),
                                                               new Date("01/31/2011"),
                                                               new Date("01/31/2011"),
                                                               new Date("01/31/2011"),
                                                               false,
                                                               true));

        OFX payrollOfx = new OFX();
        payrollOfx.setSIGNONMSGSRQV1(OFXRequestGenerator.generateSignOnMessage(psid, DataLoadServices.PIN));
        IPAYROLLTRNRQ ipayrolltrnrq = OFXRequestGenerator.generatePayrollRequest(false,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 payrollRuns);
        payrollOfx.setIPAYROLLMSGSRQV1(OFXRequestGenerator.generatePayrollMessage(company, true, ipayrolltrnrq));

        QBDTTestHelper.submitQBDTRequestStringResponse(payrollOfx);

        OFXAssert.assertPayrolls(company, payrollOfx);

        // submit update
        IPAYROLLRUN ipayrollrun = payrollRuns.get(0);
        ipayrollrun.getIPAYCHKMOD().addAll(ipayrollrun.getIPAYCHK());
        ipayrollrun.getIPAYCHK().clear();
        assertEquals("paychecks", 0, ipayrollrun.getIPAYCHK().size());
        assertEquals("paycheck mods", 5, ipayrollrun.getIPAYCHKMOD().size());

        int count = 0;
        for (IPAYCHK ipaychk : ipayrollrun.getIPAYCHKMOD()) {
            for (IADJLINE iadjline : ipaychk.getIADJLINE()) {
                count++;
                iadjline.setIEXPBYJOB("N");
                iadjline.setIQTY(count + "");
            }
            for (IHRLYWAGELINE ihrlywageline : ipaychk.getIHRLYWAGELINE()) {
                count++;
                ihrlywageline.setIJOB("job " + count);
                ihrlywageline.setICLASS("class " + count);
                ihrlywageline.setIITEM("item " + count);
                ihrlywageline.setIWCCODE("wc " + count);
            }
            for (ISALARYLINE isalaryline : ipaychk.getISALARYLINE()) {
                count++;
                isalaryline.setIJOB("job " + count);
                isalaryline.setICLASS("class " + count);
                isalaryline.setIITEM("item " + count);
                isalaryline.setIWCCODE("wc " + count);
            }
        }

        payrollOfx = new OFX();
        payrollOfx.setSIGNONMSGSRQV1(OFXRequestGenerator.generateSignOnMessage(psid, DataLoadServices.PIN));
        ipayrolltrnrq = OFXRequestGenerator.generatePayrollRequest(false,
                                                                   null,
                                                                   null,
                                                                   null,
                                                                   null,
                                                                   null,
                                                                   null,
                                                                   null,
                                                                   null,
                                                                   null,
                                                                   null,
                                                                   payrollRuns);
        payrollOfx.setIPAYROLLMSGSRQV1(OFXRequestGenerator.generatePayrollMessage(DataLoadServices.refreshCompany(company), true, ipayrolltrnrq));

        QBDTTestHelper.submitQBDTRequestStringResponse(payrollOfx);

        OFXAssert.assertPayrolls(company, payrollOfx);
    }

