    public void testHistoricalPaymentsUnderAndOverLiabilityFromPriorQuarterAndCurrent(QBOFX.OFXPayrollTransactionTransactionType pTransactionType) throws Exception {
        String psid = "123456789";
        Date quarterToStart = new Date("01/01/2011");
        List<String> overPaymentLawIds = new ArrayList<String>();
        overPaymentLawIds.add("61");
        overPaymentLawIds.add("62");
        overPaymentLawIds.add("63");
        List<String> underPaymentLawIds = new ArrayList<String>();
        underPaymentLawIds.add("64");
        underPaymentLawIds.add("1");

        DataLoadServices.updateIRSPaymentTemplateSupportDate(SpcfCalendar.createInstance(2008, 1, 1));

        PayrollServices.beginUnitOfWork();
        PSPDate.setPSPTime(SpcfCalendar.createInstance(2011, 4, 1, SpcfTimeZone.getLocalTimeZone()));
        PayrollServices.commitUnitOfWork();

        Company company = DataLoadServices.newCompany(SourceSystemCode.QBDT, psid, false, ServiceCode.Tax);
        DataLoadServices.activateTaxServiceExceptBalanceFile(company);

        OFX ofx = OFXRequestGenerator.generateBalanceFile(psid, false, false, true, false);

        OFX overpaymentBalanceFile = new OFX();
        overpaymentBalanceFile.setSIGNONMSGSRQV1(OFXRequestGenerator.generateSignOnMessage(psid, DataLoadServices.PIN));

        PayrollServices.beginUnitOfWork();
        List<IEMP> employees = ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIEMP();
        List<IPITEM> payrollItems = ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIPITEM();
        int payrollItemId = 1;
        for (Iterator<IPITEM> iterator = payrollItems.iterator(); iterator.hasNext(); ) {
            IPITEM ipitem = iterator.next();
            PayrollItem payrollItem = new PayrollItem(ipitem);
            Law law = SourceSystemLawAssoc.findLawBySourceSystemAndSourceId(SourceSystemCode.QBDT, payrollItem.getSourceLawId());
            if (overPaymentLawIds.contains(law.getLawId()) || underPaymentLawIds.contains(law.getLawId())) {
                ipitem.setIPITEMID(payrollItemId++ + "");
            } else {
                iterator.remove();
            }
        }
        PayrollServices.rollbackUnitOfWork();

        List<IPAYROLLRUN> payrollRuns = new ArrayList<IPAYROLLRUN>();
        payrollRuns.add(OFXRequestGenerator.generatePayrollRun(employees,
                                                               payrollItems,
                                                               new Date("03/31/2011"),
                                                               new Date("03/31/2011"),
                                                               new Date("03/31/2011"),
                                                               true));

        payrollRuns.add(OFXRequestGenerator.generatePayrollRun(employees,
                                                               payrollItems,
                                                               new Date("04/01/2011"),
                                                               new Date("04/01/2011"),
                                                               new Date("04/01/2011"),
                                                               true));

        // updated the tax amounts to match the payroll item id
        String underPaidPayrollPaycheckId = null;
        for (IPAYROLLRUN ipayrollrun : payrollRuns) {
            for (IPAYCHK ipaychk : ipayrollrun.getIPAYCHK()) {
                if (underPaidPayrollPaycheckId == null && ipayrollrun.getIDTPAYCHKS().equals("20110401")) {
                    underPaidPayrollPaycheckId = ipaychk.getIPAYCHKID();
                }
                for (ITAXLINE itaxline : ipaychk.getITAXLINE()) {
                    if (itaxline.getIAMT().contains("-")) {
                        itaxline.setIAMT("$-" + itaxline.getIPITEMID() + ".00");
                    } else {
                        itaxline.setIAMT("$" + itaxline.getIPITEMID() + ".00");
                    }
                }
            }
        }

        List<IPAYROLLTX> payrollTransactions = new ArrayList<IPAYROLLTX>();
        List<ITXLINE> itxlines = new ArrayList<ITXLINE>();
        int priorPaymentTotal = 0;
        for (IPITEM payrollItem : payrollItems) {
            int amount = 0;
            PayrollItem payroll = new PayrollItem(payrollItem);
            Law law = SourceSystemLawAssoc.findLawBySourceSystemAndSourceId(SourceSystemCode.QBDT, payroll.getSourceLawId());
            if (overPaymentLawIds.contains(law.getLawId())) {
                amount = Integer.parseInt(payrollItem.getIPITEMID()) * 5 + 1;
            } else if (underPaymentLawIds.contains(law.getLawId())) {
                amount = Integer.parseInt(payrollItem.getIPITEMID()) * 5 - 1;
            }
            priorPaymentTotal += amount;
            itxlines.add(OFXRequestGenerator.generateTransactionLine(null,
                                                                     new SpcfMoney(SpcfDecimal.createInstance(amount)),
                                                                     null,
                                                                     false,
                                                                     null,
                                                                     payrollItem.getIPITEMID(),
                                                                     null,
                                                                     null));
        }

        payrollTransactions.add(OFXRequestGenerator.generatePayrollTransaction(null,
                                                                               new SpcfMoney(SpcfDecimal.createInstance(-priorPaymentTotal)),
                                                                               null,
                                                                               new Date("03/31/2011"),
                                                                               new Date("03/31/2011"),
                                                                               null,
                                                                               null,
                                                                               null,
                                                                               false,
                                                                               pTransactionType,
                                                                               null,
                                                                               false,
                                                                               itxlines));

        payrollTransactions.add(OFXRequestGenerator.generatePayrollTransaction(null,
                                                                               new SpcfMoney(SpcfDecimal.createInstance(-priorPaymentTotal)),
                                                                               null,
                                                                               new Date("04/01/2011"),
                                                                               new Date("04/01/2011"),
                                                                               null,
                                                                               null,
                                                                               null,
                                                                               false,
                                                                               pTransactionType,
                                                                               null,
                                                                               false,
                                                                               itxlines));

        IPAYROLLTRNRQ ipayrolltrnrq = OFXRequestGenerator.generatePayrollRequest(true,
                                                                                 quarterToStart,
                                                                                 employees,
                                                                                 null,
                                                                                 null,
                                                                                 payrollItems,
                                                                                 null,
                                                                                 null,
                                                                                 payrollTransactions,
                                                                                 null,
                                                                                 null,
                                                                                 payrollRuns);
        overpaymentBalanceFile.setIPAYROLLMSGSRQV1(OFXRequestGenerator.generatePayrollMessage(company.getCurrentToken() + "", true, ipayrolltrnrq));

        PayrollServices.beginUnitOfWork();
        CompanyDTO companyDTO = new CompanyDTO();
        companyDTO.setCurrentToken(company.getCurrentToken());
        companyDTO.setNextEmployeeId(company.getNextEmployeeId());
        companyDTO.setNextPaycheckId(company.getNextPaycheckId());
        companyDTO.setNextPayrollTransactionId(Long.toString(Long.parseLong(company.getNextPayrollTransactionId()) + 1));
        // this is pay item
        companyDTO.setNextPayrollItemId(company.getNextPayrollItemId());
        PayrollServices.companyManager.updateCompanyTokensAndIdsCore(company.getSourceSystemCd(), company.getSourceCompanyId(), companyDTO, true);
        PayrollServices.commitUnitOfWork();

        com.intuit.sbd.payroll.psp.common.ofx.response.OFX response = QBDTTestHelper.submitQBDTRequest(overpaymentBalanceFile);

        IPAYROLLRS ipayrollrs = response.getIPAYROLLMSGSRSV1().getIPAYROLLUPDATERS().getIPAYROLLTRNRS().getIPAYROLLRS();
        assertNotNull("Payroll response", ipayrollrs);

        // verify the liab check
        assertEquals("liability checks", 2, ipayrollrs.getIPAYROLLTX().size());
        com.intuit.sbd.payroll.psp.common.ofx.response.IPAYROLLTX ipayrolltx = ipayrollrs.getIPAYROLLTX().get(1);

        OFXAssert.assertNonVoidLiabilityCheckExceptTransactionLines(company, ipayrolltx, underPaidPayrollPaycheckId, null, null, null);

        int total = 0;
        // each item should be under paid by $1
        for (com.intuit.sbd.payroll.psp.common.ofx.response.ITXLINE itxline : ipayrolltx.getITXLINE()) {
            assertNotNull("payroll item id", itxline.getIPITEMID());
            int amount = 1;
            total += amount;
            assertEquals("amount", "$" + amount + ".00", itxline.getIAMT());
        }

        assertEquals("amount", "$-" + total + ".00", ipayrolltx.getIAMT());

        PayrollServices.beginUnitOfWork();
        assertEquals("Number of PayrollRuns", 4, PayrollRun.findPayrollRuns(company).size());
        DomainEntitySet<PayrollRun> adjustmentPayrollRuns = PayrollRun.findPayrollRunsByType(company, null, null, PayrollType.Adjustment);
        assertEquals("Number of PayrollRuns", 2, adjustmentPayrollRuns.size());
        int priorQuarterAdjustmentPayrollIndex = 0;
        int currentQuarterAdjustmentPayrollIndex = 1;
        SpcfCalendar liabilityAdjustmentEffectiveDateForPriorQuarter = SpcfCalendar.createInstance(2011, 3, 31, SpcfTimeZone.getLocalTimeZone());
        SpcfCalendar liabilityAdjustmentEffectiveDateForCurrentQuarter = PSPDate.getPSPTime().copy();
        SpcfCalendar currentQuarterAdjustmentPaycheckDate;
        SpcfCalendar liabilityEffectiveDate;
        CalendarUtils.clearTime(liabilityAdjustmentEffectiveDateForCurrentQuarter);
        if (adjustmentPayrollRuns.get(0).getPaycheckDate().toLocal().equals(liabilityAdjustmentEffectiveDateForPriorQuarter)) {
            assertEquals("Paycheck settlement Date prior quarter adjustment Payroll", liabilityAdjustmentEffectiveDateForPriorQuarter, adjustmentPayrollRuns.get(0).getPaycheckDate().toLocal());
            currentQuarterAdjustmentPaycheckDate = adjustmentPayrollRuns.get(1).getPaycheckDate().toLocal();
            CalendarUtils.clearTime(currentQuarterAdjustmentPaycheckDate);
            assertEquals("Paycheck settlement Date current quarter adjustment Payroll", liabilityAdjustmentEffectiveDateForCurrentQuarter, currentQuarterAdjustmentPaycheckDate);
        } else {
            priorQuarterAdjustmentPayrollIndex = 1;
            currentQuarterAdjustmentPayrollIndex = 0;
            assertEquals("Paycheck Date prior quarter adjustment Payroll", liabilityAdjustmentEffectiveDateForPriorQuarter, adjustmentPayrollRuns.get(1).getPaycheckDate().toLocal());
            currentQuarterAdjustmentPaycheckDate = adjustmentPayrollRuns.get(0).getPaycheckDate().toLocal();
            CalendarUtils.clearTime(currentQuarterAdjustmentPaycheckDate);
            assertEquals("Paycheck Date current quarter adjustment Payroll", liabilityAdjustmentEffectiveDateForCurrentQuarter, currentQuarterAdjustmentPaycheckDate);
        }
        assertEquals("Number of Liability adjustments for the adjustment payroll", 3, adjustmentPayrollRuns.get(currentQuarterAdjustmentPayrollIndex).getLiabilityAdjustmentCollection().size());
        assertEquals("Number of Liability adjustments for the adjustment payroll", 5, adjustmentPayrollRuns.get(priorQuarterAdjustmentPayrollIndex).getLiabilityAdjustmentCollection().size());
        for (LiabilityAdjustment liabilityAdjustment : adjustmentPayrollRuns.get(currentQuarterAdjustmentPayrollIndex).getLiabilityAdjustmentCollection()) {
            assertEquals("Number of Liability adjustment Amount", new SpcfMoney("1.00"), liabilityAdjustment.getAmount());
            assertTrue("Liability adjustment Law Id does not belong to Over paid Law", overPaymentLawIds.contains(liabilityAdjustment.getLaw().getLawId()));
            liabilityEffectiveDate = liabilityAdjustment.getEffectiveDate().toLocal();
            CalendarUtils.clearTime(liabilityEffectiveDate);
            assertEquals("Current Quarter Liability Adjustment effective Date", liabilityAdjustmentEffectiveDateForCurrentQuarter, liabilityEffectiveDate);
        }
        for (LiabilityAdjustment liabilityAdjustment : adjustmentPayrollRuns.get(priorQuarterAdjustmentPayrollIndex).getLiabilityAdjustmentCollection()) {
            if (overPaymentLawIds.contains(liabilityAdjustment.getLaw().getLawId())) {
                assertEquals("Number of Liability adjustment Amount", new SpcfMoney("1.00"), liabilityAdjustment.getAmount());
                assertTrue("Liability adjustment Law Id does not belong to Over paid Law", overPaymentLawIds.contains(liabilityAdjustment.getLaw().getLawId()));
            } else {
                assertEquals("Number of Liability adjustment Amount", new SpcfMoney("-1.00"), liabilityAdjustment.getAmount());
                assertTrue("Liability adjustment Law Id does not belong to Under paid Law", underPaymentLawIds.contains(liabilityAdjustment.getLaw().getLawId()));
            }
            assertEquals("Prior Quarter Liability Adjustment effective Date", liabilityAdjustmentEffectiveDateForPriorQuarter, liabilityAdjustment.getEffectiveDate().toLocal());
        }
        DomainEntitySet<FinancialTransaction> eRFinancialTransactions = FinancialTransaction.findAllFinancialTransaction(company, TransactionTypeCode.EmployerTaxDebit);
        assertEquals("ER Tax debits", 2, eRFinancialTransactions.size());
        assertEquals("ER Tax debits", new SpcfMoney("2.00"), eRFinancialTransactions.get(0).getFinancialTransactionAmount());
        assertEquals("ER Tax debits", new SpcfMoney("2.00"), eRFinancialTransactions.get(1).getFinancialTransactionAmount());
        DomainEntitySet<FinancialTransaction> agencyTaxCreditFinancialTransactions = FinancialTransaction.findAllFinancialTransaction(company, TransactionTypeCode.AgencyTaxCredit);
        assertEquals("Number of AgencyTaxCredit Financial Transactions", 4, agencyTaxCreditFinancialTransactions.size());
        for (FinancialTransaction agencyTaxCreditFinancialTransaction : agencyTaxCreditFinancialTransactions) {
            assertEquals("AgencyTaxCredit Amount", new SpcfMoney("1.00"), agencyTaxCreditFinancialTransaction.getFinancialTransactionAmount());
            assertTrue("AgencyTaxCredit Law Id does not belong to Under paid Law", underPaymentLawIds.contains(agencyTaxCreditFinancialTransaction.getLaw().getLawId()));
        }
        assertEquals("Number of HPDE Financial Transactions", 10, FinancialTransaction.findAllFinancialTransaction(company, TransactionTypeCode.AgencyHPDETaxPayment).size());
        DomainEntitySet<MoneyMovementTransaction> eftpsMoneyMovementTransactions = MoneyMovementTransaction.findTaxPayments().setCompany(company).setOnHold().find();
        assertEquals("Number of EFTPS MMTs", 2, eftpsMoneyMovementTransactions.size());
        assertEquals("Number of EFTPS MMT Amount", new SpcfMoney("2.00"), eftpsMoneyMovementTransactions.get(0).getMoneyMovementTransactionAmount());
        DomainEntitySet<MoneyMovementTransaction> hpdeMMTs = Application.find(MoneyMovementTransaction.class, MoneyMovementTransaction.MoneyMovementPaymentMethod().equalTo(PaymentMethod.HPDE));
        assertEquals("Number of HPDE MMTs", 2, hpdeMMTs.size());
        assertEquals("Number of HPDE MMT Amount", new SpcfMoney("76.00"), hpdeMMTs.get(0).getMoneyMovementTransactionAmount());
        assertEquals("Number of HPDE MMT Amount", new SpcfMoney("76.00"), hpdeMMTs.get(1).getMoneyMovementTransactionAmount());
        PayrollServices.commitUnitOfWork();
    }

