        TaxPaymentDTO taxPaymentDTO2 = new TaxPaymentDTO();
        taxPaymentDTO2.setLawId("64");
        taxPaymentDTO2.setPayrollItemId(CompanyLaw.findCompanyLaw(company, "64").getSourceId());
        taxPaymentDTO2.setQBDTTransactionInfoDTO(new QBDTTransactionInfoDTO());
        taxPaymentDTO2.setDate(new DateDTO("2011-01-31"));
        taxPaymentDTO2.setAmount(new SpcfMoney("5.00"));

        TaxPaymentDTO taxPaymentDTO3 = new TaxPaymentDTO();
        taxPaymentDTO3.setLawId("63");
        taxPaymentDTO3.setPayrollItemId(CompanyLaw.findCompanyLaw(company, "63").getSourceId());
        taxPaymentDTO3.setQBDTTransactionInfoDTO(new QBDTTransactionInfoDTO());
        taxPaymentDTO3.setDate(new DateDTO("2011-01-31"));
        taxPaymentDTO3.setAmount(new SpcfMoney("5.00"));

        TaxPaymentDTO taxPaymentDTO4 = new TaxPaymentDTO();
        taxPaymentDTO4.setLawId("62");
        taxPaymentDTO4.setPayrollItemId(CompanyLaw.findCompanyLaw(company, "62").getSourceId());
        taxPaymentDTO4.setQBDTTransactionInfoDTO(new QBDTTransactionInfoDTO());
        taxPaymentDTO4.setDate(new DateDTO("2011-01-31"));
        taxPaymentDTO4.setAmount(new SpcfMoney("5.00"));

        TaxPaymentDTO taxPaymentDTO5 = new TaxPaymentDTO();
        taxPaymentDTO5.setLawId("61");
        taxPaymentDTO5.setPayrollItemId(CompanyLaw.findCompanyLaw(company, "61").getSourceId());
        taxPaymentDTO5.setQBDTTransactionInfoDTO(new QBDTTransactionInfoDTO());
        taxPaymentDTO5.setDate(new DateDTO("2011-01-31"));
        taxPaymentDTO5.setAmount(new SpcfMoney("5.00"));

        List<TaxPaymentDTO> taxPaymentDTOs = new ArrayList<TaxPaymentDTO>();
        taxPaymentDTOs.add(taxPaymentDTO1);
        taxPaymentDTOs.add(taxPaymentDTO2);
        taxPaymentDTOs.add(taxPaymentDTO3);
        taxPaymentDTOs.add(taxPaymentDTO4);
        taxPaymentDTOs.add(taxPaymentDTO5);
        priorPaymentDTO.setTaxes(taxPaymentDTOs);

        priorPaymentSubmissionDTO.getPayments().put("IRS-941-PAYMENT", priorPaymentDTO);
        priorPaymentSubmissionDTOs.add(priorPaymentSubmissionDTO);

        ProcessResult processResult = PayrollServices.paymentManager.submitPriorPaymentsTax(company.getSourceSystemCd(), company.getSourceCompanyId(), priorPaymentSubmissionDTOs);
        assertSuccess("Prior payments are not submitted", processResult);
        PayrollServices.commitUnitOfWork();

        PayrollServices.beginUnitOfWork();
        assertEquals("Number of PayrollRuns", 2, PayrollRun.findPayrollRuns(company).size());
        DomainEntitySet<PayrollRun> adjustmentPayrollRuns = PayrollRun.findPayrollRunsByType(company, null, null, PayrollType.Adjustment);
