    public void testVoidUnderpaidPayrollAfterOffload(QBOFX.OFXPayrollTransactionTransactionType pTransactionType) throws Exception {
        testLiabilityHistoricalUnderPayments(pTransactionType);

        String psid = "123456789";
        Company company = Company.findCompany(psid, SourceSystemCode.QBDT);

        OffloadACHTransactions offloader;

        // offload Agency Tax Credits
        PayrollServices.beginUnitOfWork();
        PSPDate.setPSPTime(SpcfCalendar.createInstance(2011, 1, 27, SpcfTimeZone.getLocalTimeZone()));
        PayrollServices.commitUnitOfWork();
        offloader = new OffloadACHTransactions();
        offloader.offloadAndPostOffload(OffloadGroup.Codes.STANDARD, PSPDate.getPSPTime());

        PayrollServices.beginUnitOfWork();
        PSPDate.setPSPTime(SpcfCalendar.createInstance(2011, 1, 29, SpcfTimeZone.getLocalTimeZone()));
        PayrollServices.commitUnitOfWork();

        ProcessACHTransactions processAchTransactions = new ProcessACHTransactions();
        processAchTransactions.process(PSPDate.getPSPTime());

        PayrollRun payroll = PayrollRun.findPayrollRuns(company).get(0);

        VoidPayrollDTO voidPayrollDTO = new VoidPayrollDTO();
        voidPayrollDTO.setSourcePayrollRunId(payroll.getSourcePayRunId());

        PayrollServices.beginUnitOfWork();
        ProcessResult voidProcessResult = PayrollServices.payrollManager.voidPayroll(SourceSystemCode.QBDT, psid, voidPayrollDTO);
        PayrollServices.commitUnitOfWork();
        assertSuccess(voidProcessResult);

        // make sure all paychecks are voided
        PayrollServices.beginUnitOfWork();
        PayrollRun payrollRun = PayrollRun.findPayrollRun(company, payroll.getSourcePayRunId());
        for (Paycheck paycheck : payrollRun.getPaycheckCollection()) {
            assertEquals("voided", PaycheckStatusCode.Inactive, paycheck.getStatus());
        }
        Application.rollbackUnitOfWork();
    }

