    private List<IPAYROLLRUN> submit100kPayroll(String pPsid,
                                                OFX pOfx,
                                                Date pPaycheckDate,
                                                Date pPeriodBeginDate,
                                                Date pPeriodEndDate) throws MalformedOFXException, OFXToJavaMappingError {
        return submit100kPayroll(pPsid, pOfx, pPaycheckDate, pPeriodBeginDate, pPeriodEndDate, true);
    }

    private List<IPAYROLLRUN> submit100kPayroll(String pPsid,
                                                OFX pOfx,
                                                Date pPaycheckDate,
                                                Date pPeriodBeginDate,
                                                Date pPeriodEndDate,
                                                boolean pInclude940) throws MalformedOFXException, OFXToJavaMappingError {
        DataLoadServices.updateEffectiveDepositFreqEffDate(pPsid, "IRS-941-PAYMENT", DepositFrequencyCode.QUARTERLY, SpcfCalendar.createInstance(2008, 1, 1));
        PayrollServices.beginUnitOfWork();
        Company company = Company.findCompany(pPsid, SourceSystemCode.QBDT);
        PayrollServices.rollbackUnitOfWork();

        // generate 5 paychecks
        List<IPAYROLLRUN> payrollRuns = new ArrayList<IPAYROLLRUN>();
        payrollRuns.add(OFXRequestGenerator.generatePayrollRun(pOfx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIEMP(),
                                                               pOfx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIPITEM(),
                                                               pPaycheckDate,
                                                               pPeriodBeginDate,
                                                               pPeriodEndDate,
                                                               true));

        PayrollServices.beginUnitOfWork();
        CompanyLaw aeic = CompanyLaw.findCompanyLaw(Company.findCompany(pPsid, SourceSystemCode.QBDT), "143");
        CompanyLaw futa = CompanyLaw.findCompanyLaw(Company.findCompany(pPsid, SourceSystemCode.QBDT), "66");
        PayrollServices.rollbackUnitOfWork();

        // updated the tax amounts to match the payroll item id
        for (IPAYROLLRUN payrollRun : payrollRuns) {
            for (IPAYCHK ipaychk : payrollRun.getIPAYCHK()) {
                for (Iterator<ITAXLINE> iterator = ipaychk.getITAXLINE().iterator(); iterator.hasNext(); ) {
                    ITAXLINE itaxline = iterator.next();
                    if (itaxline.getIPITEMID().equals(aeic.getSourceId()) || (itaxline.getIPITEMID().equals(futa.getSourceId()) && !pInclude940)) {
                        iterator.remove();
                    } else {
                        if (itaxline.getIAMT().contains("-")) {
                            itaxline.setIAMT("$-" + itaxline.getIPITEMID() + "0000.00");
                        } else {
                            itaxline.setIAMT("$" + itaxline.getIPITEMID() + "0000.00");
                        }
                    }
                }
            }
        }

        OFX payrollOfx = new OFX();
        payrollOfx.setSIGNONMSGSRQV1(OFXRequestGenerator.generateSignOnMessage(pPsid, DataLoadServices.PIN));
        IPAYROLLTRNRQ ipayrolltrnrq = OFXRequestGenerator.generatePayrollRequest(false,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 payrollRuns);
        payrollOfx.setIPAYROLLMSGSRQV1(OFXRequestGenerator.generatePayrollMessage(company, true, ipayrolltrnrq));

        com.intuit.sbd.payroll.psp.common.ofx.response.OFX response = QBDTTestHelper.submitQBDTRequest(payrollOfx);
        IPAYROLLRS ipayrollrs = response.getIPAYROLLMSGSRSV1().getIPAYROLLUPDATERS().getIPAYROLLTRNRS().getIPAYROLLRS();
        assertNotNull("Payroll response", ipayrollrs);

        assertEquals("liability checks", 2, ipayrollrs.getIPAYROLLTX().size());

        PayrollServices.beginUnitOfWork();
        company = Company.findCompany(pPsid, SourceSystemCode.QBDT);
        CompanyBankAccount companyBankAccount = company.getCompanyBankAccountCollection().get(0);

        SpcfCalendar paycheckDate = SpcfCalendar.createInstance(pPaycheckDate.getTime());
        CalendarUtils.clearTime(paycheckDate);
        DomainEntitySet<PayrollRun> domainPayrollRuns = Application.find(PayrollRun.class, PayrollRun.Company().equalTo(company).And(PayrollRun.PaycheckDate().greaterThan(paycheckDate)));

        assertEquals(1, domainPayrollRuns.size());
        PayrollRun payrollRun = domainPayrollRuns.get(0);
        for (com.intuit.sbd.payroll.psp.common.ofx.response.IPAYROLLTX ipayrolltx : ipayrollrs.getIPAYROLLTX()) {
            assertEquals("account name", companyBankAccount.getSourceBankAccountName(), ipayrolltx.getIACCTNAME());
            assertEquals("cleared", "0", ipayrolltx.getICLEARED());
            assertEquals("on service", "Y", ipayrolltx.getIONSERVICE());
            assertEquals("void", "N", ipayrolltx.getIVOID());
            assertEquals("memo", QBOFX.MEMOS.CREATED_BY_PAYROLL_SERVICE + QBOFX.DATE_FORMATTER.format(SpcfUtils.convertSpcfCalendarToDate(PSPDate.getPSPTime())), ipayrolltx.getIMEMO());
            assertNotNull("id", ipayrolltx.getIPAYROLLTXID());
            assertEquals("period end date", QBOFX.getDTTXResponse(SpcfUtils.convertSpcfCalendarToDate(payrollRun.getPaycheckDate())), ipayrolltx.getIDTPAYPDEND());

            FinancialTransaction erDebit = null;
            if (QBOFX.AGENCIES.QUICKBOOKS_PAYROLL_SERVICE.equals(ipayrolltx.getINAME())) {
                DomainEntitySet<FinancialTransaction> erTaxDebit = payrollRun.getFinancialTransactionCollection().find(FinancialTransaction.TransactionType().TransactionTypeCd().equalTo(TransactionTypeCode.EmployerTaxDebit));
                assertNotNull("er debit", erTaxDebit.get(0));
                erDebit = erTaxDebit.get(0);
            } else if (QBOFX.AGENCIES.INTERNAL_REVENUE_SERVICE.equals(ipayrolltx.getINAME())) {
                DomainEntitySet<FinancialTransaction> directDebit = payrollRun.getFinancialTransactionCollection().find(FinancialTransaction.TransactionType().TransactionTypeCd().equalTo(TransactionTypeCode.AgencyDirectCredit));
                assertNotNull("er debit", directDebit.get(0));
                erDebit = directDebit.get(0);
            } else {
                fail("name = " + ipayrolltx.getINAME());
            }

            assertEquals("transaction date", QBOFX.getDTTXResponse(SpcfUtils.convertSpcfCalendarToDate(erDebit.getSettlementDate())), ipayrolltx.getIDTTX());
            SpcfDecimal total = SpcfMoney.ZERO;
            for (com.intuit.sbd.payroll.psp.common.ofx.response.ITXLINE itxline : ipayrolltx.getITXLINE()) {
                if (itxline.getIMEMO() != null && itxline.getIMEMO().equals(QBOFX.MEMOS.DEBIT_REDUCED.APPLIED_OVERPAID_TAX_FUNDS)) {
                    assertNotNull("payroll item id", itxline.getIPITEMID());
                    SpcfMoney overpaymentAmount = QBOFX.mapOFXStringToMoney(itxline.getIAMT());
                    assertTrue("overpayment is not negative", overpaymentAmount.isLessThan(SpcfMoney.ZERO));
                    total = total.add(overpaymentAmount);
                } else {
                    if (itxline.getIPITEMID() == null || itxline.getIISDD() != null) {
                        // fees and dd
                        SpcfMoney amount = QBOFX.mapOFXStringToMoney(itxline.getIAMT());
                        total = total.add(amount);
                    } else {
                        int amount = Integer.parseInt(itxline.getIPITEMID()) * 50000;
                        assertEquals("amount", "$" + amount + ".00", itxline.getIAMT());
                        total = total.add(SpcfDecimal.createInstance(amount));
                    }
                }
            }

            assertEquals("amount", "$-" + total.toString(), ipayrolltx.getIAMT());
        }
        PayrollServices.rollbackUnitOfWork();

        QBDTTestHelper.assertNoErrorRequests(company);

        PayrollServices.beginUnitOfWork();
        company = Company.findCompany(company.getSourceCompanyId(), company.getSourceSystemCd());
        OFXAssert.assertPayrolls(payrollOfx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIPAYROLLRUN(), company);
        OFXAssert.assertPayrollTransactions(payrollOfx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIPAYROLLTX(), company);
        PayrollServices.rollbackUnitOfWork();
        return payrollRuns;
    }

    @Test
    public void testHistoricalPaymentsExceedLiabilityWithLiabChk() throws Exception {
        String psid = "123456789";
        Date quarterToStart = new Date("01/01/2011");
        List<String> lawIds = new ArrayList<String>();
        lawIds.add("61");
        lawIds.add("62");
        lawIds.add("63");
        lawIds.add("64");
        lawIds.add("1");

        DataLoadServices.updateIRSPaymentTemplateSupportDate(SpcfCalendar.createInstance(2008, 1, 1));

        PayrollServices.beginUnitOfWork();
        PSPDate.setPSPTime(SpcfCalendar.createInstance(2011, 1, 25, SpcfTimeZone.getLocalTimeZone()));
        PayrollServices.commitUnitOfWork();

        Company company = DataLoadServices.newCompany(SourceSystemCode.QBDT, psid, false, ServiceCode.Tax);
        DataLoadServices.activateTaxServiceExceptBalanceFile(company);

        OFX ofx = OFXRequestGenerator.generateBalanceFile(psid, false, false, true, false);

        OFX overpaymentBalanceFile = new OFX();
        overpaymentBalanceFile.setSIGNONMSGSRQV1(OFXRequestGenerator.generateSignOnMessage(psid, DataLoadServices.PIN));

        PayrollServices.beginUnitOfWork();
        List<IEMP> employees = ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIEMP();
        List<IPITEM> payrollItems = ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIPITEM();
        int payrollItemId = 1;
        for (Iterator<IPITEM> iterator = payrollItems.iterator(); iterator.hasNext(); ) {
            IPITEM ipitem = iterator.next();
            PayrollItem payrollItem = new PayrollItem(ipitem);
            Law law = SourceSystemLawAssoc.findLawBySourceSystemAndSourceId(SourceSystemCode.QBDT, payrollItem.getSourceLawId());
            if (lawIds.contains(law.getLawId())) {
                ipitem.setIPITEMID(payrollItemId++ + "");
            } else {
                iterator.remove();
            }
        }
        PayrollServices.rollbackUnitOfWork();

        List<IPAYROLLRUN> payrollRuns = new ArrayList<IPAYROLLRUN>();
        payrollRuns.add(OFXRequestGenerator.generatePayrollRun(employees,
                                                               payrollItems,
                                                               new Date("01/31/2011"),
                                                               new Date("01/31/2011"),
                                                               new Date("01/31/2011"),
                                                               true));

        // updated the tax amounts to match the payroll item id
        for (IPAYROLLRUN ipayrollrun : payrollRuns) {
            for (IPAYCHK ipaychk : ipayrollrun.getIPAYCHK()) {
                for (ITAXLINE itaxline : ipaychk.getITAXLINE()) {
                    if (itaxline.getIAMT().contains("-")) {
                        itaxline.setIAMT("$-" + itaxline.getIPITEMID() + ".00");
                    } else {
                        itaxline.setIAMT("$" + itaxline.getIPITEMID() + ".00");
                    }
                }
            }
        }

        List<IPAYROLLTX> payrollTransactions = new ArrayList<IPAYROLLTX>();
        List<ITXLINE> itxlines = new ArrayList<ITXLINE>();
        double priorPaymentTotal = 0;
        for (IPITEM payrollItem : payrollItems) {
            double amount = (Double.parseDouble(payrollItem.getIPITEMID()) * 5.0 + 1.0) / 2.0;
            priorPaymentTotal += amount;
            itxlines.add(OFXRequestGenerator.generateTransactionLine(null,
                                                                     new SpcfMoney(SpcfDecimal.createInstance(amount)),
                                                                     null,
                                                                     false,
                                                                     null,
                                                                     payrollItem.getIPITEMID(),
                                                                     null,
                                                                     null));
        }

        payrollTransactions.add(OFXRequestGenerator.generatePayrollTransaction(null,
                                                                               new SpcfMoney(SpcfDecimal.createInstance(-priorPaymentTotal)),
                                                                               null,
                                                                               new Date("01/31/2011"),
                                                                               new Date("01/31/2011"),
                                                                               null,
                                                                               null,
                                                                               null,
                                                                               false,
                                                                               QBOFX.OFXPayrollTransactionTransactionType.PRIORPMT,
                                                                               null,
                                                                               false,
                                                                               itxlines));

        payrollTransactions.add(OFXRequestGenerator.generatePayrollTransaction(null,
                                                                               new SpcfMoney(SpcfDecimal.createInstance(-priorPaymentTotal)),
                                                                               null,
                                                                               new Date("01/31/2011"),
                                                                               new Date("01/31/2011"),
                                                                               null,
                                                                               null,
                                                                               null,
                                                                               false,
                                                                               QBOFX.OFXPayrollTransactionTransactionType.LIABCHK,
                                                                               null,
                                                                               false,
                                                                               itxlines));


        IPAYROLLTRNRQ ipayrolltrnrq = OFXRequestGenerator.generatePayrollRequest(true,
                                                                                 quarterToStart,
                                                                                 employees,
                                                                                 null,
                                                                                 null,
                                                                                 payrollItems,
                                                                                 null,
                                                                                 null,
                                                                                 payrollTransactions,
                                                                                 null,
                                                                                 null,
                                                                                 payrollRuns);
        overpaymentBalanceFile.setIPAYROLLMSGSRQV1(OFXRequestGenerator.generatePayrollMessage(company.getCurrentToken() + "", true, ipayrolltrnrq));

        QBDTTestHelper.submitQBDTRequestStringResponse(overpaymentBalanceFile);

        PayrollServices.beginUnitOfWork();
        assertEquals("Number of PayrollRuns", 2, PayrollRun.findPayrollRuns(company).size());
        DomainEntitySet<PayrollRun> adjustmentPayrollRuns = PayrollRun.findPayrollRunsByType(company, null, null, PayrollType.Adjustment);
        assertEquals("Number of PayrollRuns", 1, adjustmentPayrollRuns.size());
        assertEquals("Number of PayrollRuns", PayrollStatus.Complete, adjustmentPayrollRuns.get(0).getPayrollRunStatus());
        DomainEntitySet<FinancialTransaction> eRFinancialTransactions = FinancialTransaction.findAllFinancialTransaction(company, TransactionTypeCode.EmployerTaxDebit);
        assertEquals("ER Tax debits", 0, eRFinancialTransactions.size());
        DomainEntitySet<FinancialTransaction> agencyTaxCreditFinancialTransactions = FinancialTransaction.findAllFinancialTransaction(company, TransactionTypeCode.AgencyTaxCredit);
        assertEquals("Number of AgencyTaxCredit Financial Transactions", 0, agencyTaxCreditFinancialTransactions.size());
        assertEquals("Number of HPDE Financial Transactions", 10, FinancialTransaction.findAllFinancialTransaction(company, TransactionTypeCode.AgencyHPDETaxPayment).size());
        DomainEntitySet<MoneyMovementTransaction> eftpsMoneyMovementTransactions = MoneyMovementTransaction.findTaxPayments().setCompany(company).setOnHold().find();
        assertEquals("Number of EFTPS MMTs", 0, eftpsMoneyMovementTransactions.size());
        DomainEntitySet<MoneyMovementTransaction> hpdeMMTs = Application.find(MoneyMovementTransaction.class, MoneyMovementTransaction.MoneyMovementPaymentMethod().equalTo(PaymentMethod.HPDE));
        assertEquals("Number of HPDE MMTs", 2, hpdeMMTs.size());
        assertEquals("Number of HPDE MMT Amount", new SpcfMoney("40.00"), hpdeMMTs.get(0).getMoneyMovementTransactionAmount());
        assertEquals("Number of HPDE MMT Amount", new SpcfMoney("40.00"), hpdeMMTs.get(1).getMoneyMovementTransactionAmount());
        assertEquals("Number of First PayrollReceived event", 0, CompanyEvent.getEventCountByType(company, EventTypeCode.FirstPayrollReceived));
        PayrollServices.commitUnitOfWork();
    }

    @Test
    public void testLiabilityHistoricalOverAndUnderPaymentsWithPayrollOnQuarterToStartDate() throws Exception {
        String psid = "123456789";
        Date quarterToStart = new Date("01/01/2011");
        List<String> overPaymentLawIds = new ArrayList<String>();
        overPaymentLawIds.add("61");
        overPaymentLawIds.add("62");
        overPaymentLawIds.add("63");
        List<String> underPaymentLawIds = new ArrayList<String>();
        underPaymentLawIds.add("64");
        underPaymentLawIds.add("1");

        DataLoadServices.updateIRSPaymentTemplateSupportDate(SpcfCalendar.createInstance(2008, 1, 1));

        PayrollServices.beginUnitOfWork();
        PSPDate.setPSPTime(SpcfCalendar.createInstance(2011, 3, 8, SpcfTimeZone.getLocalTimeZone()));
        PayrollServices.commitUnitOfWork();

        Company company = DataLoadServices.newCompany(SourceSystemCode.QBDT, psid, false, ServiceCode.Tax);
        DataLoadServices.activateTaxServiceExceptBalanceFile(company);

        OFX ofx = OFXRequestGenerator.generateBalanceFile(psid, false, false, true, false);

        OFX overpaymentBalanceFile = new OFX();
        overpaymentBalanceFile.setSIGNONMSGSRQV1(OFXRequestGenerator.generateSignOnMessage(psid, DataLoadServices.PIN));

        PayrollServices.beginUnitOfWork();
        List<IEMP> employees = ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIEMP();
        List<IPITEM> payrollItems = ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIPITEM();
        int payrollItemId = 1;
        for (Iterator<IPITEM> iterator = payrollItems.iterator(); iterator.hasNext(); ) {
            IPITEM ipitem = iterator.next();
            PayrollItem payrollItem = new PayrollItem(ipitem);
            Law law = SourceSystemLawAssoc.findLawBySourceSystemAndSourceId(SourceSystemCode.QBDT, payrollItem.getSourceLawId());
            if (overPaymentLawIds.contains(law.getLawId()) || underPaymentLawIds.contains(law.getLawId())) {
                ipitem.setIPITEMID(payrollItemId++ + "");
            } else {
                iterator.remove();
            }
        }
        PayrollServices.rollbackUnitOfWork();

        List<IPAYROLLRUN> payrollRuns = new ArrayList<IPAYROLLRUN>();
        payrollRuns.add(OFXRequestGenerator.generatePayrollRun(employees,
                                                               payrollItems,
                                                               new Date("03/01/2011"),
                                                               new Date("01/01/2011"),
                                                               new Date("01/01/2011"),
                                                               true));
        // updated the tax amounts to match the payroll item id
        for (IPAYROLLRUN ipayrollrun : payrollRuns) {
            for (IPAYCHK ipaychk : ipayrollrun.getIPAYCHK()) {
                for (ITAXLINE itaxline : ipaychk.getITAXLINE()) {
                    int itemId = Integer.parseInt(itaxline.getIPITEMID());
                    if (itaxline.getIAMT().contains("-")) {
                        itaxline.setIAMT("$-" + itemId + ".00");
                    } else {
                        itaxline.setIAMT("$" + itemId + ".00");
                    }
                }
            }
        }
        List<IPAYROLLTX> payrollTransactions = new ArrayList<IPAYROLLTX>();
        List<ITXLINE> itxlines = new ArrayList<ITXLINE>();
        int priorPaymentTotal = 0;
        for (IPITEM payrollItem : payrollItems) {
            int amount = 0;
            PayrollItem payroll = new PayrollItem(payrollItem);
            Law law = SourceSystemLawAssoc.findLawBySourceSystemAndSourceId(SourceSystemCode.QBDT, payroll.getSourceLawId());
            if (overPaymentLawIds.contains(law.getLawId())) {
                amount = Integer.parseInt(payrollItem.getIPITEMID()) * 5 + 1;
            } else if (underPaymentLawIds.contains(law.getLawId())) {
                amount = Integer.parseInt(payrollItem.getIPITEMID()) * 5 - 1;
            }
            priorPaymentTotal += amount;
            itxlines.add(OFXRequestGenerator.generateTransactionLine(null,
                                                                     new SpcfMoney(SpcfDecimal.createInstance(amount)),
                                                                     null,
                                                                     false,
                                                                     null,
                                                                     payrollItem.getIPITEMID(),
                                                                     null,
                                                                     null));
        }

        payrollTransactions.add(OFXRequestGenerator.generatePayrollTransaction(null,
                                                                               new SpcfMoney(SpcfDecimal.createInstance(-priorPaymentTotal)),
                                                                               null,
                                                                               new Date("03/01/2011"),
                                                                               new Date("01/01/2011"),
                                                                               null,
                                                                               null,
                                                                               null,
                                                                               false,
                                                                               QBOFX.OFXPayrollTransactionTransactionType.PRIORPMT,
                                                                               null,
                                                                               false,
                                                                               itxlines));

        IPAYROLLTRNRQ ipayrolltrnrq = OFXRequestGenerator.generatePayrollRequest(true,
                                                                                 quarterToStart,
                                                                                 employees,
                                                                                 null,
                                                                                 null,
                                                                                 payrollItems,
                                                                                 null,
                                                                                 null,
                                                                                 payrollTransactions,
                                                                                 null,
                                                                                 null,
                                                                                 payrollRuns);
        overpaymentBalanceFile.setIPAYROLLMSGSRQV1(OFXRequestGenerator.generatePayrollMessage(company.getCurrentToken() + "", true, ipayrolltrnrq));

        com.intuit.sbd.payroll.psp.common.ofx.response.OFX response = QBDTTestHelper.submitQBDTRequest(overpaymentBalanceFile);

        IPAYROLLRS ipayrollrs = response.getIPAYROLLMSGSRSV1().getIPAYROLLUPDATERS().getIPAYROLLTRNRS().getIPAYROLLRS();
        assertNotNull("Payroll response", ipayrollrs);

        // verify the liab check
        assertEquals("liability checks", 1, ipayrollrs.getIPAYROLLTX().size());
        com.intuit.sbd.payroll.psp.common.ofx.response.IPAYROLLTX ipayrolltx = ipayrollrs.getIPAYROLLTX().get(0);

        DomainEntitySet<PayrollRun> regularPayroll = PayrollRun.findPayrollRunsByType(company, null, null, PayrollType.CloudOnly);
        assertEquals("Number of CloundOnly PayrollRuns", 1, regularPayroll.size());

        OFXAssert.assertNonVoidLiabilityCheckExceptTransactionLines(company,
                                                                    ipayrolltx,
                                                                    null,
                                                                    null,
                                                                    null,
                                                                    regularPayroll.get(0));
        int total = 0;
        // each item should be under paid by $1
        for (com.intuit.sbd.payroll.psp.common.ofx.response.ITXLINE itxline : ipayrolltx.getITXLINE()) {
            assertNotNull("payroll item id", itxline.getIPITEMID());
            int amount = 1;
            total += amount;
            assertEquals("amount", "$" + amount + ".00", itxline.getIAMT());
        }

        assertEquals("amount", "$-" + total + ".00", ipayrolltx.getIAMT());

        PayrollServices.beginUnitOfWork();
        assertEquals("Number of PayrollRuns", 2, PayrollRun.findPayrollRuns(company).size());
        DomainEntitySet<PayrollRun> adjustmentPayrollRuns = PayrollRun.findPayrollRunsByType(company, null, null, PayrollType.Adjustment);
        assertEquals("Number of PayrollRuns", 1, adjustmentPayrollRuns.size());
        assertEquals("Number of Liability adjustments for the adjustment payroll", 3, adjustmentPayrollRuns.get(0).getLiabilityAdjustmentCollection().size());
        for (LiabilityAdjustment liabilityAdjustment : adjustmentPayrollRuns.get(0).getLiabilityAdjustmentCollection()) {
            assertEquals("Number of Liability adjustment Amount", new SpcfMoney("1.00"), liabilityAdjustment.getAmount());
            assertTrue("Liability adjustment Law Id does not belong to Over paid Law", overPaymentLawIds.contains(liabilityAdjustment.getLaw().getLawId()));
        }
        DomainEntitySet<FinancialTransaction> eRFinancialTransactions = FinancialTransaction.findAllFinancialTransaction(company, TransactionTypeCode.EmployerTaxDebit);
        assertEquals("ER Tax debits", 1, eRFinancialTransactions.size());
        assertEquals("ER Tax debits", new SpcfMoney("2.00"), eRFinancialTransactions.get(0).getFinancialTransactionAmount());
        DomainEntitySet<FinancialTransaction> agencyTaxCreditFinancialTransactions = FinancialTransaction.findAllFinancialTransaction(company, TransactionTypeCode.AgencyTaxCredit);
        assertEquals("Number of AgencyTaxCredit Financial Transactions", 2, agencyTaxCreditFinancialTransactions.size());
        for (FinancialTransaction agencyTaxCreditFinancialTransaction : agencyTaxCreditFinancialTransactions) {
            assertEquals("AgencyTaxCredit Amount", new SpcfMoney("1.00"), agencyTaxCreditFinancialTransaction.getFinancialTransactionAmount());
            assertTrue("AgencyTaxCredit Law Id does not belong to Under paid Law", underPaymentLawIds.contains(agencyTaxCreditFinancialTransaction.getLaw().getLawId()));
        }
        assertEquals("Number of HPDE Financial Transactions", 5, FinancialTransaction.findAllFinancialTransaction(company, TransactionTypeCode.AgencyHPDETaxPayment).size());
        DomainEntitySet<MoneyMovementTransaction> eftpsMoneyMovementTransactions = MoneyMovementTransaction.findTaxPayments().setCompany(company).setOnHold().find();
        assertEquals("Number of EFTPS MMTs", 1, eftpsMoneyMovementTransactions.size());
        assertEquals("Number of EFTPS MMT Amount", new SpcfMoney("2.00"), eftpsMoneyMovementTransactions.get(0).getMoneyMovementTransactionAmount());
        DomainEntitySet<MoneyMovementTransaction> hpdeMMTs = Application.find(MoneyMovementTransaction.class, MoneyMovementTransaction.MoneyMovementPaymentMethod().equalTo(PaymentMethod.HPDE));
        assertEquals("Number of HPDE MMTs", 1, hpdeMMTs.size());
        assertEquals("Number of HPDE MMT Amount", new SpcfMoney("76.00"), hpdeMMTs.get(0).getMoneyMovementTransactionAmount());
        PayrollServices.commitUnitOfWork();
    }

