    @Test
    public void testBalfWithVoids() throws Exception {
        String psid = "123456789";
        DataLoadServices.updateIRSPaymentTemplateSupportDate(SpcfCalendar.createInstance(2008, 1, 1));

        Company company = DataLoadServices.newCompany(SourceSystemCode.QBDT, psid, false, ServiceCode.Tax);
        DataLoadServices.activateTaxServiceExceptBalanceFile(company);

        OFX ofx = OFXRequestGenerator.generateBalanceFile(psid, true);

        for (IPAYROLLRUN ipayrollrun : ofx.getIPAYROLLMSGSRQV1().getIPAYROLLUPDATERQ().getIPAYROLLTRNRQ().getIPAYROLLRQ().getIPAYROLLRUN()) {
            for (IPAYCHK ipaychk : ipayrollrun.getIPAYCHK()) {
                ipaychk.setIVOID(QBOFX.Y_N(true));
            }
            // don't void the first check in the payroll so that we get a liability check back
            ipayrollrun.getIPAYCHK().get(0).setIVOID(QBOFX.Y_N(false));
            ipayrollrun.getIPAYCHK().get(0).setIPAYCHKTYPE("PAYCHK");
        }

        com.intuit.sbd.payroll.psp.common.ofx.response.OFX response = QBDTTestHelper.submitQBDTRequest(ofx);
        assertEquals("Voids not expected in response", 0, response.getIPAYROLLMSGSRSV1().getIPAYROLLUPDATERS().getIPAYROLLTRNRS().getIPAYROLLRS().getIPAYCHKMOD().size());
    }

