    @Test
    public void testLiabilityAdjustments_MultipleAdjustments() throws Exception {
        String psid = "123456789";
        DataLoadServices.updateIRSPaymentTemplateSupportDate(SpcfCalendar.createInstance(2008, 1, 1));

        Company company = DataLoadServices.newCompany(SourceSystemCode.QBDT, psid, false, ServiceCode.Tax);
        DataLoadServices.activateTaxServiceExceptBalanceFile(company);

        OFX ofx = QBDTTestHelper.submitBalanceFile(company, true);

        DataLoadServices.updateEffectiveDepositFreqEffDate(psid, "IRS-941-PAYMENT", DepositFrequencyCode.QUARTERLY);

        DataLoadServices.setPSPDate(2012, 3, 20);
        QBDTTestHelper.submitPayroll(company, ofx, new Date("03/25/2012"), new Date("03/25/2012"), new Date("03/25/2012"), false);
        QBDTTestHelper.submitPayroll(company, ofx, new Date("04/15/2012"), new Date("04/15/2012"), new Date("04/15/2012"), false);

        PayrollServices.beginUnitOfWork();
        CompanyLaw fica_er = CompanyLaw.findCompanyLaw(company, Law.ERFICA);
        PayrollServices.rollbackUnitOfWork();

        // positive adjustment
        List<IPAYROLLTX> liabilityAdjustments = new ArrayList<IPAYROLLTX>();
        List<ITXLINE> itxlines = new ArrayList<ITXLINE>();
        itxlines.add(OFXRequestGenerator.generateTransactionLine(null,
                                                                 new SpcfMoney(SpcfDecimal.createInstance(-120)),
                                                                 "Class" + fica_er.getSourceId(),
                                                                 false,
                                                                 "Memo" + fica_er.getSourceId(),
                                                                 fica_er.getSourceId(),
                                                                 new SpcfMoney(SpcfDecimal.createInstance(fica_er.getSourceId() + 1)),
                                                                 new SpcfMoney(SpcfDecimal.createInstance(fica_er.getSourceId() + 2))));

        // negative adjustment
        List<ITXLINE> itxlines2 = new ArrayList<ITXLINE>();
        itxlines2.add(OFXRequestGenerator.generateTransactionLine(null,
                                                                  new SpcfMoney(SpcfDecimal.createInstance(115)),
                                                                  "Class" + fica_er.getSourceId(),
                                                                  false,
                                                                  "Memo" + fica_er.getSourceId(),
                                                                  fica_er.getSourceId(),
                                                                  new SpcfMoney(SpcfDecimal.createInstance(fica_er.getSourceId() + 1)),
                                                                  new SpcfMoney(SpcfDecimal.createInstance(fica_er.getSourceId() + 2))));

        liabilityAdjustments.add(OFXRequestGenerator.generatePayrollTransaction("Account" + 1,
                                                                                new SpcfMoney(SpcfDecimal.createInstance(-1200)),
                                                                                "" + 1,
                                                                                new Date("03/27/2012"),
                                                                                new Date("03/27/2012"),
                                                                                null,
                                                                                "Memo " + 1,
                                                                                "Agency" + 1,
                                                                                true,
                                                                                QBOFX.OFXPayrollTransactionTransactionType.LIABADJ,
                                                                                "Ref" + 1,
                                                                                false,
                                                                                itxlines));
        for (int i = 0; i < 10; i++) {
            liabilityAdjustments.add(OFXRequestGenerator.generatePayrollTransaction("Account" + 1,
                                                                                    new SpcfMoney(SpcfDecimal.createInstance(1200)),
                                                                                    "" + 1,
                                                                                    new Date("03/31/2012"),
                                                                                    new Date("03/31/2012"),
                                                                                    null,
                                                                                    "Memo " + 1,
                                                                                    "Agency" + 1,
                                                                                    true,
                                                                                    QBOFX.OFXPayrollTransactionTransactionType.LIABADJ,
                                                                                    "Ref" + 1,
                                                                                    false,
                                                                                    itxlines2));
        }

        OFX adjustmentOfx = new OFX();
        adjustmentOfx.setSIGNONMSGSRQV1(OFXRequestGenerator.generateSignOnMessage(psid, DataLoadServices.PIN));
        IPAYROLLTRNRQ ipayrolltrnrq = OFXRequestGenerator.generatePayrollRequest(false,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 null,
                                                                                 liabilityAdjustments,
                                                                                 null,
                                                                                 null,
                                                                                 null);
        adjustmentOfx.setIPAYROLLMSGSRQV1(OFXRequestGenerator.generatePayrollMessage(DataLoadServices.refreshCompany(company).getCurrentToken() + "", true, ipayrolltrnrq));

        DataLoadServices.setPSPDate(2012, 3, 28);
        com.intuit.sbd.payroll.psp.common.ofx.response.OFX response = QBDTTestHelper.submitQBDTRequest(adjustmentOfx);
        assertNotNull("Response", response);
        IPAYROLLRS ipayrollrs = response.getIPAYROLLMSGSRSV1().getIPAYROLLUPDATERS().getIPAYROLLTRNRS().getIPAYROLLRS();
        assertNotNull("Payroll response", ipayrollrs);

        // PSRV003392 - ER payable was applied multiple times when there were multiple adjustments
        // check to make sure that ER payable is zero after credit application
        assertEquals("ATR", SpcfMoney.ZERO, LedgerAccount.getLedgerAccountBalance(company, LedgerAccountCode.AgencyTaxRefund));
        assertEquals("ER Payable", SpcfMoney.ZERO, LedgerAccount.getLedgerAccountBalance(company, LedgerAccountCode.ERPayable));
    }

