    //PSP-7323/PSP-7122 - Tax transactions in balance file with in current quarter are ignored by PSP because of the
    // 7 day limit of the MMT transaction, this is causing problems leading to pending liabilities which are not
    // offloaded in PSP. The solution is to allow MMT for balance file even if it crosses 7 day threshold
    @Test
    public void testBalanceFileWithTaxTransactionsInPast() throws IOException {
        DataLoadServices.updateIRSPaymentTemplateSupportDate(SpcfCalendar.createInstance(2008, 1, 1));
        String psid = "105868803";
        DataLoadServices.setPSPDate(2014, 8, 20);
        Company company = Company.findCompany(psid, SourceSystemCode.QBDT);
        if (company == null) {
            company = DataLoadServices.newCompany(SourceSystemCode.QBDT, psid, psid, false, ServiceCode.DirectDeposit, ServiceCode.Tax);
            DataLoadServices.addCompanyPIN(company, DataLoadServices.PIN);
            DataLoadServices.activateDDService(company);
            DataLoadServices.enrollEFTPS(company);
            DataLoadServices.enrollACH(company);
            DataLoadServices.activateTaxServiceExceptBalanceFile(company);
        }
        String OFX = AssistedUnprocessedRequestTests.readFile(Application.findFileOnClassPath("resources/ofx/balance_file_taxes_past_threshold_1.xml"));
        System.out.println(QBDTTestHelper.submitQBDTRequestStringResponse(OFX, true));

        //IRS-941-PAYMENT
        //Verify FIT
        PayrollServices.beginUnitOfWork();
        SpcfMoney pendingTaxPaymentAfterBalfFIT = getPendingTaxPaymentAfterBalfForQuarterAndLaw(company, Law.FIT, 3, 2014);
        Criterion<FinancialTransaction> ftCriteria = FinancialTransaction.SettlementTypeCd().equalTo(SettlementType.EFTPS)
                                                                         .And(FinancialTransaction.Law().LawId().equalTo(Law.FIT))
                                                                         .And(FinancialTransaction.TransactionType().TransactionTypeCd().equalTo(TransactionTypeCode.AgencyTaxCredit))
                                                                         .And(FinancialTransaction.CurrentTransactionState().TransactionStateCd().equalTo(TransactionStateCode.Created));
        DomainEntitySet<FinancialTransaction> fitFts = Application.find(FinancialTransaction.class, ftCriteria);
        assertEquals(2, fitFts.size());
        assertEquals(pendingTaxPaymentAfterBalfFIT, fitFts.get(0).getFinancialTransactionAmount().add(fitFts.get(1).getFinancialTransactionAmount()));

        //Verify FICA EE
        SpcfMoney pendingTaxPaymentAfterBalfFICAEE = getPendingTaxPaymentAfterBalfForQuarterAndLaw(company, Law.EEFICA, 3, 2014);
        ftCriteria = FinancialTransaction.SettlementTypeCd().equalTo(SettlementType.EFTPS)
                                         .And(FinancialTransaction.Law().LawId().equalTo(Law.EEFICA))
                                         .And(FinancialTransaction.TransactionType().TransactionTypeCd().equalTo(TransactionTypeCode.AgencyTaxCredit))
                                         .And(FinancialTransaction.CurrentTransactionState().TransactionStateCd().equalTo(TransactionStateCode.Created));
        DomainEntitySet<FinancialTransaction> ficaEEFts = Application.find(FinancialTransaction.class, ftCriteria);
        assertEquals(3, ficaEEFts.size());
        assertEquals(pendingTaxPaymentAfterBalfFICAEE, ficaEEFts.get(0).getFinancialTransactionAmount().
                add(ficaEEFts.get(1).getFinancialTransactionAmount()).add(ficaEEFts.get(2).getFinancialTransactionAmount()));

        //Verify FICA ER
        SpcfMoney pendingTaxPaymentAfterBalfFICAER = getPendingTaxPaymentAfterBalfForQuarterAndLaw(company, Law.ERFICA, 3, 2014);
        ftCriteria = FinancialTransaction.SettlementTypeCd().equalTo(SettlementType.EFTPS)
                                         .And(FinancialTransaction.Law().LawId().equalTo(Law.ERFICA))
                                         .And(FinancialTransaction.TransactionType().TransactionTypeCd().equalTo(TransactionTypeCode.AgencyTaxCredit))
                                         .And(FinancialTransaction.CurrentTransactionState().TransactionStateCd().equalTo(TransactionStateCode.Created));
        DomainEntitySet<FinancialTransaction> ficaERFts = Application.find(FinancialTransaction.class, ftCriteria);
        assertEquals(2, ficaERFts.size());
        assertEquals(pendingTaxPaymentAfterBalfFICAER, ficaERFts.get(0).getFinancialTransactionAmount().add(ficaERFts.get(1).getFinancialTransactionAmount()));
        Application.rollbackUnitOfWork();

        //Now we have verified that tax transaction are created for a balance file containing taxes
        //Lets verify that if now we send a payroll past 7 days, no transactions are created for it
        PayrollServices.beginUnitOfWork();
        PSPDate.setPSPTime(SpcfCalendar.createInstance(2014, 8, 29, SpcfTimeZone.getLocalTimeZone()));
        PayrollServices.commitUnitOfWork();

        PayrollRun payrollRun = DataLoadPalette.runSimpleTaxPayroll(company, new DateDTO(2014, 8, 21));

        PayrollServices.beginUnitOfWork();
        //Verify no financial transactions created for payroll beyond threshold
        company = Company.findCompany(company.getSourceCompanyId(), company.getSourceSystemCd());
        DomainEntitySet<FinancialTransaction> financialTransactions = Application.find(FinancialTransaction.class, FinancialTransaction.Company().equalTo(company)
                                                                                                                                       .And(FinancialTransaction.PayrollRun().equalTo(payrollRun)));
        assertEquals(0, financialTransactions.size());
        //Verify no MMTs are created
        DomainEntitySet<MoneyMovementTransaction> moneyMovementTransactions = Application.find(MoneyMovementTransaction.class, MoneyMovementTransaction.Company().equalTo(company)
                                                                                                                                                       .And(MoneyMovementTransaction.FinancialTransactionSet().Filter().PayrollRun().equalTo(payrollRun)));
        assertEquals(0, moneyMovementTransactions.size());
        //Verify no fees is charged
        DomainEntitySet<BillingDetail> billingDetails = Application.find(BillingDetail.class, BillingDetail.PayrollRun().equalTo(payrollRun));
        assertEquals("Billing details", 0, billingDetails.size());
        PayrollServices.rollbackUnitOfWork();

        //Lets verify that for a regular payroll everything is working as expected
        PayrollServices.beginUnitOfWork();
        PSPDate.setPSPTime(SpcfCalendar.createInstance(2014, 8, 29, SpcfTimeZone.getLocalTimeZone()));
        PayrollServices.commitUnitOfWork();

        PayrollRun payrollRun2 = DataLoadPalette.runSimpleTaxPayroll(company, new DateDTO(2014, 8, 28));

        PayrollServices.beginUnitOfWork();
        //Verify financial transactions created for payroll within threshold
        company = Company.findCompany(company.getSourceCompanyId(), company.getSourceSystemCd());
        financialTransactions = Application.find(FinancialTransaction.class, FinancialTransaction.Company().equalTo(company)
                                                                                                 .And(FinancialTransaction.PayrollRun().equalTo(payrollRun2)));
        assertEquals(19, financialTransactions.size());
        //Verify  MMTs are created
        moneyMovementTransactions = Application.find(MoneyMovementTransaction.class, MoneyMovementTransaction.Company().equalTo(company)
                                                                                                             .And(MoneyMovementTransaction.FinancialTransactionSet().Filter().PayrollRun().equalTo(payrollRun2)));
        assertEquals(11, moneyMovementTransactions.size());
        //Verify fees is charged
        billingDetails = Application.find(BillingDetail.class, BillingDetail.PayrollRun().equalTo(payrollRun2));
        assertEquals("Billing details", 1, billingDetails.size());
        PayrollServices.rollbackUnitOfWork();

    }

    public SpcfMoney getPendingTaxPaymentAfterBalfForQuarterAndLaw(Company company, String lawId, int quarter, int year) {
        DomainEntitySet<Tax> taxesDue = Application.find(Tax.class, Tax.Law().LawId().equalTo(lawId)
                                                                       .And(Tax.Paycheck().PayrollRun().PaycheckDate().
                                                                               between(CalendarUtils.getFirstDayOfQuarter(year, quarter),
                                                                                       CalendarUtils.getLastDayOfQuarter(year, quarter)))
                                                                       .And(Tax.Company().equalTo(company)));
        DomainEntitySet<LiabilityAdjustment> liabAdjustments = Application.find(LiabilityAdjustment.class, LiabilityAdjustment.Law().LawId().equalTo(lawId)
                                                                                                                              .And(LiabilityAdjustment.PayrollRun().PaycheckDate().
                                                                                                                                      between(CalendarUtils.getFirstDayOfQuarter(year, quarter),
                                                                                                                                              CalendarUtils.getLastDayOfQuarter(year, quarter)))
                                                                                                                              .And(LiabilityAdjustment.Company().equalTo(company)));
        SpcfMoney totalTaxesDueAmount = new SpcfMoney("0.00");
        for (Tax tax : taxesDue) {
            totalTaxesDueAmount = (SpcfMoney) totalTaxesDueAmount.add(tax.getTaxLiabilityAmount());
        }
        SpcfMoney totalTaxesAndAdjustments = (SpcfMoney) (new SpcfMoney("0.00")).add(totalTaxesDueAmount);
        for (LiabilityAdjustment liabilityAdjustment : liabAdjustments) {
            totalTaxesAndAdjustments = (SpcfMoney) totalTaxesAndAdjustments.add(liabilityAdjustment.getAmount());
        }
        DomainEntitySet<FinancialTransaction> ftsForPaymentRecordedHPDE = Application.find(FinancialTransaction.class, FinancialTransaction.Law().LawId().equalTo(lawId)
                                                                                                                                           .And(FinancialTransaction.SettlementTypeCd().equalTo(SettlementType.HPDE))
                                                                                                                                           .And(FinancialTransaction.PayrollRun().PaycheckDate().between(CalendarUtils.getFirstDayOfQuarter(year, quarter), CalendarUtils.getLastDayOfQuarter(year, quarter)))
                                                                                                                                           .And(FinancialTransaction.Company().equalTo(company)));
        SpcfMoney totalPaymentRecordedByHPDE = new SpcfMoney("0.00");
        for (FinancialTransaction ft : ftsForPaymentRecordedHPDE) {
            totalPaymentRecordedByHPDE = (SpcfMoney) totalPaymentRecordedByHPDE.add(ft.getFinancialTransactionAmount());
        }

        return (SpcfMoney) totalTaxesAndAdjustments.subtract(totalPaymentRecordedByHPDE);
    }

