    private void verifyLiabilityAdjustmentAmounts(Company company, String lawId, SpcfMoney taxAmount, SpcfMoney wageAmount) {
        PayrollServices.beginUnitOfWork();
        // check wage totals, stole this from the tax leger code in sap
        HqlBuilder laHql = new HqlBuilder(true, "select la.Law.LawId, sum(la.Amount), sum(la.TaxableWages) " +
                " from com.intuit.sbd.payroll.psp.domain.PayrollRun pr " +
                " join pr.LiabilityAdjustmentSet la " +
                "where pr.Company = :company " +
                "and pr.PaycheckDate between :checkDateStart and :checkDateEnd " +
                "and la.Law.LawId  in (:lawIds) " +
                "group by la.Law.LawId");
        laHql.setParameter("company", company);
        laHql.setParameter("checkDateStart", SpcfCalendar.createInstance(2020, SpcfCalendar.March, 29));
        laHql.setParameter("checkDateEnd", SpcfCalendar.createInstance(2020, SpcfCalendar.June, 30, 23, 59, 59, 999));
        laHql.setParameterList("lawIds", Law.IRS_CREDIT_LAWS.toArray());
        List<Object[]> liabilities = laHql.list();
        assertEquals(1, liabilities.size());
        Object[] columns = liabilities.get(0);
        assertEquals(lawId, columns[0]);
        assertEquals(taxAmount, columns[1]);
        assertEquals(wageAmount, columns[2]);
        PayrollServices.rollbackUnitOfWork();
    }
